insert into public.modules (id,course_id,titulo,ordem) values ('e6b50000-b551-4c00-9000-0000000000a1','e669a8b5-18dd-48a3-b9bf-2fefac43f0c2','Fundamentos do Áudio ao Vivo',1);
insert into public.modules (id,course_id,titulo,ordem) values ('e6b50000-b551-4c00-9000-0000000000a2','e669a8b5-18dd-48a3-b9bf-2fefac43f0c2','Equipamentos e Operação (menor porte)',2);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values
  ('e6b50000-b551-4c00-9000-0000000b0001','e6b50000-b551-4c00-9000-0000000000a1','A cadeia do som ao vivo: da voz até a caixa','texto','<p><strong>Antes de mexer em qualquer botão, entenda o caminho.</strong> Todo som que sai de uma caixa passou por uma sequência de etapas — a <strong>cadeia do som</strong>. Se você entende essa cadeia, você resolve 90% dos problemas de um show, porque quase todo "não sai som" é só uma etapa dessa corrente que travou. Esta é a primeira coisa que um técnico precisa saber.</p>
insert into public.quizzes (id,lesson_id,titulo) values ('e6b50000-b551-4c00-9000-0000000c0001','e6b50000-b551-4c00-9000-0000000b0001','Quiz — A cadeia do som ao vivo');
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('e6b50000-b551-4c00-9000-000000000101','e6b50000-b551-4c00-9000-0000000c0001','O que é a "cadeia do som"?','É a sequência de etapas por onde o sinal passa, da fonte (voz/instrumento) até a caixa acústica. Se uma etapa trava, o som não chega.',1,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000101','Um tipo de cabo de microfone',false,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000101','A sequência de etapas por onde o sinal passa, da fonte até a caixa',true,2);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000101','Uma marca de mesa de som',false,3);
