insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('e6b50000-b551-4c00-9000-000000000103','e6b50000-b551-4c00-9000-0000000c0001','Um teclado, que tem saída elétrica, normalmente entra na mesa por:','Instrumentos com saída elétrica (teclado, baixo, violão com captador) entram por uma DI ou entrada de linha — não precisam de microfone.',3,1);
