insert into public.ai_animations (lesson_id,tipo,status,model,roteiro,urls) values ('e6b50000-b551-4c00-9000-0000000b0001','interactive','ready','handcrafted-interactive','{"titulo":"Simulador — A Cadeia do Som","cenas":[{"numero":1,"titulo":"Simulador — A Cadeia do Som","modo":"widget","narracao":"Monte a cadeia do som e aprenda a achar onde o sinal trava. Complete as 4 missões.","explicacao_texto":"Monte a cadeia do som e aprenda a achar onde o sinal trava. Complete as 4 missões.","destaques":["Fonte → mic/DI → cabo → mesa → amp → caixa","Níveis de sinal","Troubleshooting: achar onde travou"]}]}'::jsonb,'[{"html":"<!doctype html>\n<html lang=\"pt-BR\">\n<head>\n<meta charset=\"utf-8\">\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1\">\n<title>Simulador — A Cadeia do Som ao Vivo (SMU)</title>\n<style>\n  :root{\n    --bg:#0b0f17; --panel:#131a29; --panel2:#0e1420; --line:#233149; --ink:#e7ecf5;\n    --muted:#8ea0bd; --amber:#F59E0B; --green:#22c55e; --red:#ef4444; --cyan:#22d3ee;\n  }\n  *{box-sizing:border-box}\n  html,body{margin:0}\n  body{background:var(--bg);color:var(--ink);\n    font-family:\"Space Grotesk\",system-ui,-apple-system,\"Segoe UI\",Roboto,sans-serif;\n    -webkit-font-smoothing:antialiased;padding:10px}\n  h1{font-size:15px;margin:0 0 2px}\n  .sub{font-size:11.5px;color:var(--muted);margin-bottom:10px}\n\n  .mission{display:flex;gap:10px;align-items:center;background:#0c1220;border:1px solid var(--line);\n    border-radius:10px;padding:9px 12px;margin-bottom:12px}\n  .mission .idx{font-size:10px;color:var(--amber);font-weight:800;letter-spacing:.8px;white-space:nowrap}\n  .mission .txt{font-size:12.5px;line-height:1.3;flex:1}\n  .mission .txt b{color:var(--amber)}\n  .mission button{font:inherit;font-size:11px;color:var(--muted);background:transparent;border:1px solid var(--line);\n    border-radius:7px;padding:6px 9px;cursor:pointer}\n\n  .chain{display:flex;flex-wrap:wrap;gap:8px;align-items:stretch;justify-content:center}\n  .stage{flex:1 1 140px;min-width:130px;max-width:200px;background:linear-gradient(180deg,var(--panel),var(--panel2));\n    border:1.5px solid var(--line);border-radius:12px;padding:11px 10px;display:flex;flex-direction:column;gap:8px;\n    position:relative;transition:border-color .2s,box-shadow .2s}\n  .stage.ok{border-color:var(--green);box-shadow:0 0 0 1px var(--green) inset}\n  .stage.bad{border-color:var(--red);box-shadow:0 0 14px #ef444455}\n  .stage .ic{font-size:26px;line-height:1;text-align:center}\n  .stage .nm{font-size:12.5px;font-weight:700;text-align:center}\n  .stage .st{font-size:10.5px;color:var(--muted);text-align:center;min-height:14px}\n  .stage.bad .st{color:var(--red)}\n  .arrow{align-self:center;color:#33456a;font-size:20px;flex:0 0 auto;transition:color .15s}\n  .arrow.live{color:var(--amber);text-shadow:0 0 10px var(--amber)}\n\n  .btn{font:inherit;border:0;border-radius:8px;padding:9px 8px;font-weight:700;cursor:pointer;font-size:11.5px;\n    background:#0c1220;border:1px solid var(--line);color:var(--ink);width:100%}\n  .btn.on{background:var(--green);border-color:var(--green);color:#08120a}\n  .btn.off{background:#1a1010;border-color:#5b2626;color:#ff9a9a}\n  label.sl{font-size:10px;color:var(--muted);display:flex;justify-content:space-between}\n  input[type=range]{width:100%;accent-color:var(--amber);height:22px}\n  .meterbox{height:12px;border-radius:6px;background:#05070d;border:1px solid #1a2540;overflow:hidden}\n  .meterbox i{display:block;height:100%;width:0%;background:linear-gradient(90deg,var(--green),var(--amber) 82%,var(--red));transition:width .08s}\n\n  .controls{display:flex;gap:8px;margin-top:14px;flex-wrap:wrap;align-items:center;justify-content:center}\n  .test{background:var(--amber);color:#0b0f17;font-weight:800;border:0;border-radius:9px;padding:11px 20px;cursor:pointer;font-size:13px}\n  .reset{background:transparent;color:var(--muted);border:1px solid var(--line);border-radius:9px;padding:11px 16px;cursor:pointer;font:inherit}\n  .verdict{font-size:12.5px;font-weight:700;padding:8px 12px;border-radius:8px;min-height:18px;text-align:center;flex-basis:100%}\n  .verdict.good{color:var(--green)} .verdict.bad{color:var(--red)}\n  .spk{display:flex;flex-direction:column;gap:6px;align-items:center;justify-content:center}\n  .wave{font-size:11px;color:var(--muted)}\n  @media(max-width:560px){\n    .stage{flex-basis:100%;max-width:none;flex-direction:row;align-items:center;text-align:left}\n    .stage .ic{font-size:22px} .stage>div:nth-child(2){flex:1}\n    .arrow{transform:rotate(90deg)}\n  }\n</style>\n</head>\n<body>\n  <h1>A Cadeia do Som ao Vivo</h1>\n  <div class=\"sub\">Monte o caminho do som — da voz até a caixa — e aprenda a achar onde o sinal \"trava\".</div>\n\n  <div class=\"mission\">\n    <span class=\"idx\" id=\"mIdx\">MISSÃO 1/4</span>\n    <span class=\"txt\" id=\"mTxt\">—</span>\n    <button id=\"mSkip\">Pular</button>\n  </div>\n\n  <div class=\"chain\" id=\"chain\"></div>\n\n  <div class=\"controls\">\n    <button class=\"test\" id=\"testBtn\">▶ Testar sinal</button>\n    <button class=\"reset\" id=\"resetBtn\">Ligar tudo</button>\n    <div class=\"verdict\" id=\"verdict\"></div>\n  </div>\n\n<script>\n\"use strict\";\n(function(){\n  const state={ micOn:true, cableOn:true, gain:60, chOn:true, fader:70, ampOn:true };\n  const chain=document.getElementById(\"chain\");\n  const V=document.getElementById(\"verdict\");\n\n  // define stages\n  const stages=[\n    {id:\"src\", ic:\"🎙️\", nm:\"Fonte (Voz)\", body:st=>`<div class=\"st\">Sinal acústico</div>`, ok:()=>true},\n    {id:\"mic\", ic:\"🎤\", nm:\"Microfone\", ok:()=>state.micOn,\n      body:st=>`<button class=\"btn ${state.micOn?''on'':''off''}\" data-t=\"micOn\">${state.micOn?''LIGADO'':''DESLIGADO''}</button>\n                <div class=\"st\">Transforma som em sinal elétrico</div>`},\n    {id:\"cab\", ic:\"🔌\", nm:\"Cabo XLR\", ok:()=>state.cableOn,\n      body:st=>`<button class=\"btn ${state.cableOn?''on'':''off''}\" data-t=\"cableOn\">${state.cableOn?''CONECTADO'':''SOLTO''}</button>\n                <div class=\"st\">Leva o sinal até a mesa</div>`},\n    {id:\"mix\", ic:\"🎚️\", nm:\"Mesa de Som\", ok:()=>state.gain>5&&state.chOn&&state.fader>5,\n      body:st=>`\n        <label class=\"sl\">Ganho <span>${state.gain}</span></label><input type=\"range\" min=\"0\" max=\"100\" value=\"${state.gain}\" data-r=\"gain\">\n        <button class=\"btn ${state.chOn?''on'':''off''}\" data-t=\"chOn\">${state.chOn?''CANAL ON'':''MUTE''}</button>\n        <label class=\"sl\">Fader <span>${state.fader}</span></label><input type=\"range\" min=\"0\" max=\"100\" value=\"${state.fader}\" data-r=\"fader\">`},\n    {id:\"amp\", ic:\"🧯\", nm:\"Amplificador\", ok:()=>state.ampOn,\n      body:st=>`<button class=\"btn ${state.ampOn?''on'':''off''}\" data-t=\"ampOn\">${state.ampOn?''LIGADO'':''DESLIGADO''}</button>\n                <div class=\"st\">Dá potência para a caixa</div>`},\n    {id:\"spk\", ic:\"🔊\", nm:\"Caixa\", ok:()=>true,\n      body:st=>`<div class=\"meterbox\"><i id=\"spkMeter\"></i></div><div class=\"wave\" id=\"spkTxt\">silêncio</div>`},\n  ];\n\n  function firstBreak(){ // retorna índice do primeiro estágio que trava, ou -1\n    for(let i=0;i<stages.length;i++){ if(!stages[i].ok()) return i; } return -1;\n  }\n  function reasons(i){ return {\n    mic:\"Microfone desligado\", cab:\"Cabo solto\",\n    mix: state.gain<=5?\"Ganho no zero\": (!state.chOn?\"Canal mutado\":\"Fader embaixo\"),\n    amp:\"Amplificador desligado\" }[stages[i].id] || \"—\"; }\n\n  function render(){\n    chain.innerHTML=\"\";\n    stages.forEach((s,i)=>{\n      if(i>0){ const a=document.createElement(\"div\"); a.className=\"arrow\"; a.dataset.gap=i; a.textContent=\"➜\"; chain.appendChild(a); }\n      const d=document.createElement(\"div\"); d.className=\"stage\"; d.dataset.id=s.id;\n      d.innerHTML=`<div class=\"ic\">${s.ic}</div><div><div class=\"nm\">${s.nm}</div>${s.body(s)}</div>`;\n      chain.appendChild(d);\n    });\n    wire();\n    liveMeter();\n  }\n  function wire(){\n    chain.querySelectorAll(\"[data-t]\").forEach(b=>b.onclick=()=>{ state[b.dataset.t]=!state[b.dataset.t]; render(); check(); });\n    chain.querySelectorAll(\"[data-r]\").forEach(r=>r.oninput=()=>{ state[r.dataset.r]=+r.value;\n      r.previousElementSibling.querySelector(\"span\").textContent=r.value; liveMeter(); check(); });\n  }\n\n  // medidor da caixa em tempo real (quando a cadeia funciona)\n  let raf;\n  function chainWorks(){ return firstBreak()===-1 && stages.every(s=>s.ok()); }\n  function liveMeter(){\n    const m=document.getElementById(\"spkMeter\"), t=document.getElementById(\"spkTxt\");\n    if(!m) return;\n    if(chainWorks()){ const lvl=Math.round(state.gain*0.4+state.fader*0.55); m.style.width=lvl+\"%\";\n      t.textContent=\"🔊 som na caixa (\"+lvl+\"%)\"; t.style.color=\"var(--green)\"; }\n    else { m.style.width=\"0%\"; t.textContent=\"silêncio\"; t.style.color=\"var(--muted)\"; }\n  }\n\n  // teste animado do sinal percorrendo a cadeia\n  document.getElementById(\"testBtn\").onclick=()=>{\n    chain.querySelectorAll(\".stage\").forEach(s=>s.classList.remove(\"ok\",\"bad\"));\n    chain.querySelectorAll(\".arrow\").forEach(a=>a.classList.remove(\"live\"));\n    const brk=firstBreak();\n    const stageEls=[...chain.querySelectorAll(\".stage\")];\n    const arrowEls=[...chain.querySelectorAll(\".arrow\")];\n    let i=0;\n    const step=()=>{\n      if(i>0) arrowEls[i-1] && arrowEls[i-1].classList.add(\"live\");\n      const stop = (brk!==-1 && i>=brk);\n      if(stop){ stageEls[brk].classList.add(\"bad\");\n        V.textContent=\"✖ O sinal travou em: \"+stages[brk].nm+\" — \"+reasons(brk); V.className=\"verdict bad\"; return; }\n      stageEls[i].classList.add(\"ok\"); i++;\n      if(i<stageEls.length){ setTimeout(step,230); }\n      else { V.textContent=\"✔ Sinal completo! O som chegou na caixa.\"; V.className=\"verdict good\"; liveMeter(); check(); }\n    };\n    step();\n  };\n  document.getElementById(\"resetBtn\").onclick=()=>{ Object.assign(state,{micOn:true,cableOn:true,gain:60,chOn:true,fader:70,ampOn:true}); render(); check(); V.textContent=\"\"; };\n\n  // missões\n  const missions=[\n    { t:''Tudo começa <b>desligado</b>. Monte a cadeia: ligue o mic, conecte o cabo, suba <b>ganho</b> e <b>fader</b>, deixe o canal <b>ON</b> e ligue o amplificador — até o som chegar na caixa.'',\n      setup:()=>Object.assign(state,{micOn:false,cableOn:false,gain:0,chOn:false,fader:0,ampOn:false}), ok:chainWorks },\n    { t:''CENÁRIO — não sai som. Descubra e resolva: o <b>amplificador</b> está desligado.'',\n      setup:()=>Object.assign(state,{micOn:true,cableOn:true,gain:60,chOn:true,fader:70,ampOn:false}), ok:chainWorks },\n    { t:''CENÁRIO — sinal mudo. O <b>cabo</b> do microfone está solto. Reconecte.'',\n      setup:()=>Object.assign(state,{micOn:true,cableOn:false,gain:60,chOn:true,fader:70,ampOn:true}), ok:chainWorks },\n    { t:''CENÁRIO — o canal está <b>mutado</b> e o <b>ganho no zero</b>. Reative o canal e suba o ganho.'',\n      setup:()=>Object.assign(state,{micOn:true,cableOn:true,gain:0,chOn:false,fader:70,ampOn:true}), ok:chainWorks },\n  ];\n  let mi=0;\n  function paintMission(){ const idx=document.getElementById(\"mIdx\"), txt=document.getElementById(\"mTxt\");\n    if(mi>=missions.length){ idx.textContent=\"CONCLUÍDO\"; txt.innerHTML=\"🎓 <b>Parabéns!</b> Você entendeu a cadeia do som e já sabe caçar onde o sinal trava — a base do trabalho.\";\n      document.getElementById(\"mSkip\").style.display=\"none\"; return; }\n    idx.textContent=\"MISSÃO \"+(mi+1)+\"/\"+missions.length; txt.innerHTML=missions[mi].t; }\n  function loadMission(){ if(mi<missions.length){ missions[mi].setup(); render(); V.textContent=\"\"; } paintMission(); }\n  function check(){ if(mi>=missions.length) return; try{ if(missions[mi].ok()){ mi++; paintMission();\n      if(mi<missions.length){ setTimeout(()=>{ missions[mi].setup(); render(); },600); } } }catch(e){} }\n  document.getElementById(\"mSkip\").onclick=()=>{ if(mi<missions.length){ mi++; loadMission(); } };\n\n  render(); loadMission();\n})();\n</script>\n</body>\n</html>\n"}]'::jsonb);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values
  ('e6b50000-b551-4c00-9000-0000000b0002','e6b50000-b551-4c00-9000-0000000000a1','Cabos e conectores: XLR, P10, P2, RCA e Speakon','texto','<p><strong>Cabo é a estrada por onde o som viaja.</strong> Um técnico de som passa boa parte do trabalho ligando e desligando cabos — e a maioria dos problemas de "não sai som" ou "tá chiando" mora num cabo ou num conector errado. Nesta aula você aprende a reconhecer cada conector, saber o que é <em>balanceado</em> e o que não é, e escolher o cabo certo para cada ligação.</p>
insert into public.quizzes (id,lesson_id,titulo) values ('e6b50000-b551-4c00-9000-0000000c0002','e6b50000-b551-4c00-9000-0000000b0002','Quiz — Cabos e conectores');
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('e6b50000-b551-4c00-9000-000000000201','e6b50000-b551-4c00-9000-0000000c0002','Qual conector é o padrão para ligar um microfone na mesa?','O XLR (cânon), de 3 pinos, é balanceado e travável — padrão de microfone e de ligações profissionais.',1,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000201','P10 (plug de guitarra)',false,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000201','XLR (cânon, 3 pinos)',true,2);
