insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('e6b50000-b551-4c00-9000-000000000202','e6b50000-b551-4c00-9000-0000000c0002','Por que um cabo balanceado (XLR / P10 TRS) pode ter tiradas longas sem chiar?','Ele leva o sinal em dois fios invertidos + malha; o ruído captado nos dois é cancelado na chegada.',2,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000202','Porque é mais grosso',false,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000202','Porque cancela o ruído captado no caminho',true,2);
