insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000202','Porque tem menos pinos',false,4);
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('e6b50000-b551-4c00-9000-000000000203','e6b50000-b551-4c00-9000-0000000c0002','Para ligar o áudio de um notebook na mesa, o cabo típico é:','P2 estéreo (saída de fone do notebook) para dois P10 (canais L e R de linha da mesa).',3,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000203','XLR para XLR',false,1);
