insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000203','RCA para XLR',false,4);
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('e6b50000-b551-4c00-9000-000000000204','e6b50000-b551-4c00-9000-0000000c0002','Um teclado (saída elétrica) normalmente entra na mesa por:','Por uma DI (direct box), que transforma o sinal desbalanceado em XLR balanceado e casa a impedância.',4,1);
