insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('e6b50000-b551-4c00-9000-000000000205','e6b50000-b551-4c00-9000-0000000c0002','O que NUNCA se deve fazer com o conector Speakon (saída do amplificador)?','Speakon é nível de potência (alto-falante). Ligá-lo numa entrada da mesa queima a entrada.',5,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000205','Ligar numa caixa passiva compatível',false,1);
