insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000205','Travar o conector',false,3);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000205','Usar em cabo de alta seção',false,4);
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('e6b50000-b551-4c00-9000-000000000206','e6b50000-b551-4c00-9000-0000000c0002','Um sinal desbalanceado (P10 TS, P2, RCA) deve ser usado em:','Distâncias curtas. Acima de ~5 m começa a captar zumbido e roncar — para tiradas longas, use balanceado.',6,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000206','Distâncias curtas',true,1);
