insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000206','Somente em microfones',false,4);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values
  ('e6b50000-b551-4c00-9000-0000000b0003','e6b50000-b551-4c00-9000-0000000000a1','Analógico × Digital e gain staging: sinal forte e limpo','texto','<p><strong>"Gain staging" é o nome técnico de uma habilidade simples e decisiva:</strong> acertar o quão forte o sinal está em cada etapa. Se o sinal está fraco demais, você aumenta depois e vem junto o chiado (ruído). Se está forte demais, ele distorce. O ponto certo é <strong>forte e limpo, com folga</strong>. Esta aula te dá os conceitos por trás disso — e a diferença entre o mundo analógico e o digital.</p>
insert into public.quizzes (id,lesson_id,titulo) values ('e6b50000-b551-4c00-9000-0000000c0003','e6b50000-b551-4c00-9000-0000000b0003','Quiz — Analógico, digital e gain staging');
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('e6b50000-b551-4c00-9000-000000000301','e6b50000-b551-4c00-9000-0000000c0003','O que é gain staging?','É acertar o nível do sinal em cada etapa: forte o bastante para ficar acima do ruído, mas com folga para não distorcer.',1,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000301','Um tipo de microfone',false,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000301','Acertar o nível do sinal em cada etapa (nem fraco, nem alto demais)',true,2);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000301','Um efeito de reverb',false,3);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000301','A ordem de ligar a mesa',false,4);
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('e6b50000-b551-4c00-9000-000000000302','e6b50000-b551-4c00-9000-0000000c0003','No áudio digital, o teto absoluto de nível é:','0 dBFS. Passar de 0 causa clipping (distorção dura). Por isso se trabalha com folga abaixo de 0.',2,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000302','+12 dBFS',false,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000302','0 dBFS',true,2);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000302','-60 dBFS',false,3);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000302','Não existe teto no digital',false,4);
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('e6b50000-b551-4c00-9000-000000000303','e6b50000-b551-4c00-9000-0000000c0003','Um sinal fraco demais na entrada resulta em:','Como você precisa aumentar muito depois, o ruído/chiado de fundo sobe junto. Melhor manter bom nível já na entrada.',3,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000303','Mais distorção',false,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000303','Mais ruído/chiado ao aumentar depois',true,2);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000303','Nada, é sempre melhor',false,3);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000303','Mais grave',false,4);
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('e6b50000-b551-4c00-9000-000000000304','e6b50000-b551-4c00-9000-0000000c0003','Headroom é:','A folga entre o nível de trabalho e o teto (0 dBFS), reservada para os picos imprevisíveis da música e da fala.',4,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000304','A folga entre o nível de trabalho e o teto, para os picos',true,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000304','O ruído de fundo do sistema',false,2);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000304','O volume do retorno',false,3);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000304','Um tipo de cabo',false,4);
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('e6b50000-b551-4c00-9000-000000000305','e6b50000-b551-4c00-9000-0000000c0003','AD / DA se refere a:','Conversão Analógico→Digital (AD) e Digital→Analógico (DA), que acontece entre o microfone, a mesa digital e a saída.',5,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000305','Dois modelos de microfone',false,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000305','Conversão analógico↔digital',true,2);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000305','Ajuste de agudos e graves',false,3);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000305','Antenas de sistema sem fio',false,4);
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('e6b50000-b551-4c00-9000-000000000306','e6b50000-b551-4c00-9000-0000000c0003','Qual o alvo prático de nível ao ajustar o ganho?','Picar em torno de −18 dBFS: forte, acima do ruído, e com bastante folga (headroom) até o teto de 0.',6,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000306','Colar em 0 dBFS',false,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000306','Picar em torno de −18 dBFS',true,2);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000306','Ficar sempre abaixo de −50 dBFS',false,3);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000306','Deixar no vermelho',false,4);
insert into public.ai_animations (lesson_id,tipo,status,model,roteiro,urls) values ('e6b50000-b551-4c00-9000-0000000b0003','interactive','ready','handcrafted-interactive','{"titulo":"Simulador — Gain Staging (dBFS)","cenas":[{"numero":1,"titulo":"Simulador — Gain Staging (dBFS)","modo":"widget","narracao":"Ajuste o ganho para o pico ficar forte e limpo — sem ruído nem distorção. Compare analógico e digital. Complete as 3 missões.","explicacao_texto":"Ajuste o ganho para o pico ficar forte e limpo — sem ruído nem distorção. Compare analógico e digital. Complete as 3 missões.","destaques":["dBFS e o teto de 0","Headroom (folga para picos)","Piso de ruído","Analógico satura × digital corta"]}]}'::jsonb,'[{"html":"<!doctype html>\n<html lang=\"pt-BR\">\n<head>\n<meta charset=\"utf-8\">\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1\">\n<title>Simulador — Analógico × Digital e Gain Staging (SMU)</title>\n<style>\n  :root{--bg:#0b0f17;--panel:#151b28;--panel2:#0f1420;--line:#26344c;--ink:#e7ecf5;\n    --muted:#8ea0bd;--amber:#F59E0B;--green:#22c55e;--red:#ef4444;--cyan:#22d3ee}\n  *{box-sizing:border-box}html,body{margin:0}\n  body{background:var(--bg);color:var(--ink);font-family:\"Space Grotesk\",system-ui,-apple-system,\"Segoe UI\",Roboto,sans-serif;\n    -webkit-font-smoothing:antialiased;padding:10px;user-select:none}\n  h1{font-size:15px;margin:0 0 2px}.sub{font-size:11.5px;color:var(--muted);margin-bottom:10px}\n  .mission{display:flex;gap:10px;align-items:center;background:#0c1220;border:1px solid var(--line);border-radius:10px;padding:9px 12px;margin-bottom:12px}\n  .mission .idx{font-size:10px;color:var(--amber);font-weight:800;letter-spacing:.8px;white-space:nowrap}\n  .mission .txt{font-size:12.5px;line-height:1.3;flex:1}.mission .txt b{color:var(--amber)}\n  .mission button{font:inherit;font-size:11px;color:var(--muted);background:transparent;border:1px solid var(--line);border-radius:7px;padding:6px 9px;cursor:pointer}\n  .grid{display:flex;gap:14px;flex-wrap:wrap}\n  .card{background:linear-gradient(180deg,var(--panel),var(--panel2));border:1px solid var(--line);border-radius:12px;padding:14px}\n  .ctrl{flex:1 1 220px;display:flex;flex-direction:column;gap:12px;align-items:center}\n  .knob{display:flex;flex-direction:column;align-items:center;gap:4px}\n  .dial{width:82px;height:82px;border-radius:50%;position:relative;cursor:ns-resize;touch-action:none;\n    background:radial-gradient(circle at 50% 32%,#33415f,#151d2e 72%);border:1px solid #3a4d70;box-shadow:inset 0 3px 8px #0009}\n  .dial::after{content:\"\";position:absolute;left:50%;top:8px;width:4px;height:26px;border-radius:2px;background:var(--amber);\n    transform-origin:50% 33px;transform:translateX(-50%) rotate(var(--rot,0deg))}\n  .kv{font-size:16px;font-weight:800}.kl{font-size:10px;color:var(--muted);letter-spacing:1px}\n  .seg{display:flex;background:#0c1220;border:1px solid var(--line);border-radius:8px;overflow:hidden}\n  .seg button{font:inherit;font-size:12px;font-weight:700;padding:8px 14px;border:0;background:transparent;color:var(--muted);cursor:pointer}\n  .seg button.on{background:var(--amber);color:#0b0f17}\n  .play{font:inherit;font-size:13px;font-weight:800;padding:11px 20px;border-radius:10px;border:0;background:var(--green);color:#08120a;cursor:pointer}\n  .meterwrap{flex:0 0 130px;display:flex;gap:10px;justify-content:center}\n  .scale{display:flex;flex-direction:column;justify-content:space-between;font-size:9px;color:var(--muted);padding:4px 0;text-align:right}\n  .meter{position:relative;width:52px;height:300px;border-radius:8px;overflow:hidden;border:1px solid #1a2540;background:\n    linear-gradient(0deg,\n      #0e1a12 0%, #0e1a12 33%,          /* ruído */\n      #10241a 33%, #10241a 78%,          /* bom (verde) */\n      #241f10 78%, #241f10 92%,          /* headroom (amber) */\n      #2a1010 92%, #2a1010 100%)}        /* clip (red) */\n  .fill{position:absolute;left:0;right:0;bottom:0;height:0%;background:linear-gradient(0deg,var(--green),var(--green) 78%,var(--amber) 92%,var(--red));transition:height .05s}\n  .peak{position:absolute;left:0;right:0;height:2px;background:#fff;box-shadow:0 0 6px #fff}\n  .zone{position:absolute;left:0;right:0;border-top:1px dashed #ffffff33;font-size:8px;color:#ffffff88;padding-left:3px}\n  .info{flex:1 1 220px}\n  .info h3{margin:0 0 8px;font-size:11px;letter-spacing:1px;color:var(--muted);text-transform:uppercase}\n  .big{font-size:26px;font-weight:800}\n  .verdict{font-size:13px;font-weight:700;margin-top:8px;min-height:20px}.verdict.good{color:var(--green)}.verdict.bad{color:var(--red)}.verdict.warn{color:var(--amber)}\n  .expl{font-size:11.5px;color:var(--muted);line-height:1.45;margin-top:10px}\n  @media(max-width:640px){.meter{height:230px}}\n</style>\n</head>\n<body>\n  <h1>Analógico × Digital e Gain Staging</h1>\n  <div class=\"sub\">Ajuste o ganho para o sinal ficar forte e limpo — sem ruído (baixo demais) nem distorção (alto demais).</div>\n  <div class=\"mission\">\n    <span class=\"idx\" id=\"mIdx\">MISSÃO 1/3</span>\n    <span class=\"txt\" id=\"mTxt\">—</span>\n    <button id=\"mSkip\">Pular</button>\n  </div>\n\n  <div class=\"grid\">\n    <div class=\"card ctrl\">\n      <div class=\"knob\"><div class=\"dial\" id=\"dial\"></div><div class=\"kv\" id=\"gv\">+0 dB</div><div class=\"kl\">GANHO</div></div>\n      <div class=\"seg\"><button data-m=\"digital\" class=\"on\">Digital</button><button data-m=\"analogico\">Analógico</button></div>\n      <button class=\"play\" id=\"play\">▶ Tocar trecho</button>\n      <div class=\"expl\" id=\"modeExpl\"></div>\n    </div>\n\n    <div class=\"card meterwrap\">\n      <div class=\"scale\"><span>+6</span><span>0</span><span>-12</span><span>-24</span><span>-40</span><span>-60</span></div>\n      <div class=\"meter\" id=\"meter\">\n        <div class=\"zone\" style=\"bottom:92%\">CLIP</div>\n        <div class=\"zone\" style=\"bottom:78%\">-6</div>\n        <div class=\"zone\" style=\"bottom:55%\">alvo -18</div>\n        <div class=\"zone\" style=\"bottom:33%\">ruído</div>\n        <div class=\"fill\" id=\"fill\"></div>\n        <div class=\"peak\" id=\"peakLine\" style=\"bottom:0%\"></div>\n      </div>\n    </div>\n\n    <div class=\"card info\">\n      <h3>Leitura</h3>\n      <div class=\"big\" id=\"peakDb\">—</div>\n      <div class=\"verdict\" id=\"verdict\"></div>\n      <div class=\"expl\" id=\"expl\">O medidor mostra o quão forte o sinal está chegando. A zona <b style=\"color:var(--green)\">verde</b> é o alvo; a <b style=\"color:var(--amber)\">âmbar</b> é a reserva (headroom); a <b style=\"color:var(--red)\">vermelha</b> é distorção.</div>\n    </div>\n  </div>\n\n<script>\n\"use strict\";\n(function(){\n  const $=id=>document.getElementById(id);\n  const clamp=(v,a,b)=>Math.max(a,Math.min(b,v));\n  const state={ gain:0, mode:\"digital\", playing:false, peak:-90 };\n  const GMIN=-20,GMAX=40;\n  const SRC=-38; // pico bruto do trecho em dBFS (antes do ganho)\n\n  function rot(){ return -140+(state.gain-GMIN)/(GMAX-GMIN)*280; }\n  function db2pct(db){ return clamp((db+60)/66*100,0,100); } // -60..+6 => 0..100\n  function setGain(v){ state.gain=clamp(v,GMIN,GMAX); $(\"dial\").style.setProperty(\"--rot\",rot()+\"deg\");\n    $(\"gv\").textContent=(state.gain>0?\"+\":\"\")+Math.round(state.gain)+\" dB\"; }\n\n  // knob drag — Pointer Events (mouse + toque unificados, com pointer capture)\n  (function(){ const el=$(\"dial\");let drag=false,last=0;\n    el.addEventListener(\"pointerdown\",e=>{drag=true;last=e.clientY;el.setPointerCapture(e.pointerId);e.preventDefault();});\n    el.addEventListener(\"pointermove\",e=>{if(!drag)return;const dy=last-e.clientY;last=e.clientY;\n      setGain(state.gain+dy*(GMAX-GMIN)/160); if(!state.playing)staticShow(); check();e.preventDefault();});\n    const up=()=>drag=false;\n    el.addEventListener(\"pointerup\",up);el.addEventListener(\"pointercancel\",up);\n  })();\n  document.querySelectorAll(\".seg button\").forEach(b=>b.onclick=()=>{\n    document.querySelectorAll(\".seg button\").forEach(x=>x.classList.remove(\"on\"));b.classList.add(\"on\");\n    state.mode=b.dataset.m; modeExpl(); if(!state.playing)staticShow(); check(); });\n  function modeExpl(){ $(\"modeExpl\").innerHTML = state.mode===\"digital\"\n    ? \"<b>Digital:</b> o teto é <b>0 dBFS</b>. Passou de 0, corta seco (distorção feia). Trabalhe com folga: pico na zona verde (~−18 a −6).\"\n    : \"<b>Analógico:</b> passando do 0 ele <b>satura aos poucos</b> (mais ''quente'', menos feio que o digital), mas ainda assim evite exagerar.\"; }\n\n  function levelAt(t){ // envelope do trecho (0..1), com um pico no meio\n    const e=0.45+0.4*Math.sin(t*3)+0.25*Math.max(0,Math.sin(t*1.3));\n    return clamp(e,0,1.2);\n  }\n  function computePeakDb(env){\n    let db=SRC+state.gain + (env-1)*10; // env~1 no pico\n    if(state.mode===\"digital\") db=Math.min(db,0.5);      // teto duro\n    else db=Math.min(db, 6 - Math.max(0,db-0)*0.5);       // satura suave\n    return db;\n  }\n  function paint(db){\n    $(\"fill\").style.height=db2pct(db)+\"%\";\n    $(\"peakLine\").style.bottom=db2pct(state.peak)+\"%\";\n    $(\"peakDb\").textContent=(db>0?\"+\":\"\")+db.toFixed(1)+\" dBFS\";\n    const v=$(\"verdict\");\n    const clip = (state.mode===\"digital\" && state.peak>=0) || (state.mode===\"analogico\" && state.peak>2);\n    if(clip){ v.textContent=\"✖ Distorção! Sinal alto demais — abaixe o ganho.\"; v.className=\"verdict bad\"; }\n    else if(state.peak> -6){ v.textContent=\"⚠ Quase no teto (headroom curto).\"; v.className=\"verdict warn\"; }\n    else if(state.peak>=-20 && state.peak<=-6){ v.textContent=\"✔ Ótimo nível! Forte e com folga.\"; v.className=\"verdict good\"; }\n    else if(state.peak<=-40){ v.textContent=\"⚠ Fraco demais — sobe o ruído/chiado.\"; v.className=\"verdict warn\"; }\n    else { v.textContent=\"Sinal ok, pode ganhar um pouco mais.\"; v.className=\"verdict\"; }\n  }\n  function staticShow(){ // mostra o pico estimado sem animar\n    const db=computePeakDb(1); state.peak=db; paint(db);\n  }\n\n  let t=0,anim=null;\n  $(\"play\").onclick=()=>{ if(state.playing){ return; } state.playing=true; state.peak=-90; t=0;\n    $(\"play\").textContent=\"♪ tocando...\"; $(\"play\").disabled=true;\n    const start=performance.now();\n    const loop=()=>{ const now=(performance.now()-start)/1000; t=now;\n      const db=computePeakDb(levelAt(now)); state.peak=Math.max(state.peak,db); paint(db);\n      if(now<3.2){ anim=requestAnimationFrame(loop); }\n      else { state.playing=false; $(\"play\").textContent=\"▶ Tocar trecho\"; $(\"play\").disabled=false; paint(state.peak); check(); }\n    };\n    anim=requestAnimationFrame(loop);\n  };\n\n  const M=[\n    { t:''Clique <b>Tocar trecho</b> e ajuste o <b>GANHO</b> para o <b>pico</b> ficar na zona verde (entre −18 e −6 dBFS), sem entrar no vermelho.'',\n      ok:()=>state.peak>=-20&&state.peak<=-6&&!((state.mode===\"digital\"&&state.peak>=0)) },\n    { t:''Entenda o teto: no modo <b>Digital</b>, suba o ganho e toque de novo até <b>clipar</b> (pico chegar a 0 dBFS). Veja a distorção.'',\n      ok:()=>state.mode===\"digital\"&&state.peak>=0 },\n    { t:''Agora conserte: abaixe o ganho e toque de novo para voltar o pico à zona <b>verde</b> (sinal forte e limpo).'',\n      ok:()=>state.peak>=-20&&state.peak<=-6&&!(state.mode===\"digital\"&&state.peak>=0) },\n  ];\n  let mi=0;\n  function paintM(){const idx=$(\"mIdx\"),txt=$(\"mTxt\");\n    if(mi>=M.length){idx.textContent=\"CONCLUÍDO\";txt.innerHTML=\"🎓 <b>Isso!</b> Gain staging é isso: sinal forte com folga, longe do ruído e da distorção. Vale para qualquer mesa, analógica ou digital.\";$(\"mSkip\").style.display=\"none\";return;}\n    idx.textContent=\"MISSÃO \"+(mi+1)+\"/\"+M.length;txt.innerHTML=M[mi].t;}\n  function check(){if(mi>=M.length)return;try{if(M[mi].ok()){mi++;paintM();}}catch(e){}}\n  $(\"mSkip\").onclick=()=>{if(mi<M.length){mi++;paintM();}};\n\n  setGain(0); modeExpl(); staticShow(); paintM();\n})();\n</script>\n</body>\n</html>\n"}]'::jsonb);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values
  ('e6b50000-b551-4c00-9000-0000000b0004','e6b50000-b551-4c00-9000-0000000000a1','Dinâmica: gate e compressor','texto','<p><strong>Dinâmica é a diferença entre o som mais baixo e o mais alto de uma fonte.</strong> Uma voz sussurra e depois grita; a bateria tem um ataque forte e um corpo mais fraco. Os processadores de dinâmica — <strong>gate</strong> e <strong>compressor</strong> — servem para controlar essa variação, deixando a mixagem estável, limpa e mais alta sem estourar. Nesta aula você entende os dois e quando usar cada um.</p>
insert into public.quizzes (id,lesson_id,titulo) values ('e6b50000-b551-4c00-9000-0000000c0004','e6b50000-b551-4c00-9000-0000000b0004','Quiz — Dinâmica (gate e compressor)');
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('e6b50000-b551-4c00-9000-000000000401','e6b50000-b551-4c00-9000-0000000c0004','O que o compressor faz?','Reduz o volume automaticamente quando o sinal passa de um limite (threshold) — deixa a fonte mais constante.',1,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000401','Silencia o canal nos silêncios',false,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000401','Abaixa os picos, deixando o som mais constante',true,2);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000401','Aumenta os agudos',false,3);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000401','Cria eco',false,4);
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('e6b50000-b551-4c00-9000-000000000402','e6b50000-b551-4c00-9000-0000000c0004','O que o gate faz?','Silencia (fecha) o canal quando o sinal está abaixo de um limite — limpa ruídos e vazamentos.',2,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000402','Silencia o canal quando o som está abaixo do limite',true,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000402','Aumenta o grave',false,2);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000402','Comprime os picos',false,3);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000402','Adiciona reverb',false,4);
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('e6b50000-b551-4c00-9000-000000000403','e6b50000-b551-4c00-9000-0000000c0004','No compressor, o que é o ''ratio''?','A razão de compressão acima do threshold: 2:1 é suave, 4:1 firme, 8:1+ quase um limitador.',3,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000403','A frequência cortada',false,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000403','O quanto ele comprime acima do threshold',true,2);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000403','O tempo de reverb',false,3);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000403','O volume de saída',false,4);
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('e6b50000-b551-4c00-9000-000000000404','e6b50000-b551-4c00-9000-0000000c0004','Qual é o uso nº 1 do compressor ao vivo?','A voz principal — segura a dinâmica do cantor, que não some no verso nem estoura no refrão.',4,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000404','No reverb da sala',false,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000404','Na voz principal',true,2);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000404','Nas luzes',false,3);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000404','No cabo de rede',false,4);
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('e6b50000-b551-4c00-9000-000000000405','e6b50000-b551-4c00-9000-0000000c0004','A ordem típica na cadeia do canal é:','Gain → gate → EQ → compressor: primeiro limpa, depois molda o timbre, depois controla a dinâmica.',5,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000405','Compressor → EQ → gate → gain',false,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000405','Gain → gate → EQ → compressor',true,2);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000405','EQ → gain → reverb',false,3);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000405','Fader → gate → mute',false,4);
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('e6b50000-b551-4c00-9000-000000000406','e6b50000-b551-4c00-9000-0000000c0004','Um erro comum com gate na voz é:','Gate rápido/apertado demais corta as palavras e a respiração — soa artificial.',6,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000406','Deixá-lo desligado',false,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000406','Apertar demais e cortar palavras/respiração',true,2);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000406','Usar em condensador',false,3);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000406','Ligar o phantom',false,4);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values
  ('e6b50000-b551-4c00-9000-0000000b0005','e6b50000-b551-4c00-9000-0000000000a1','Efeitos: reverb e delay (a lógica do envio)','texto','<p><strong>Efeitos dão espaço e profundidade à mixagem.</strong> Sem eles, a voz soa "seca", colada no rosto do ouvinte. Com um pouco de reverb e delay, ela ganha ambiente, brilho e emoção — como se estivesse num lugar de verdade. Os dois efeitos mais usados ao vivo são o <strong>reverb</strong> e o <strong>delay</strong>. Nesta aula você entende os dois e, principalmente, como usá-los pela lógica dos <strong>envios (aux/FX send)</strong>.</p>
insert into public.quizzes (id,lesson_id,titulo) values ('e6b50000-b551-4c00-9000-0000000c0005','e6b50000-b551-4c00-9000-0000000b0005','Quiz — Efeitos (reverb e delay)');
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('e6b50000-b551-4c00-9000-000000000501','e6b50000-b551-4c00-9000-0000000c0005','O que é o reverb?','A soma de milhares de reflexões do som num espaço — dá ambiente e profundidade (room, hall, plate).',1,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000501','A repetição em eco',false,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000501','O ambiente/espaço (reflexões)',true,2);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000501','Um corte de grave',false,3);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000501','Um tipo de microfone',false,4);
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('e6b50000-b551-4c00-9000-000000000502','e6b50000-b551-4c00-9000-0000000c0005','O que é o delay?','A repetição do som depois de um tempo (eco). Ao vivo, sincronizado ao ritmo da música (tap tempo).',2,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000502','O ambiente da sala',false,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000502','A repetição do som (eco), no tempo da música',true,2);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000502','Um compressor',false,3);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000502','Um padrão polar',false,4);
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('e6b50000-b551-4c00-9000-000000000503','e6b50000-b551-4c00-9000-0000000c0005','Como o efeito é normalmente aplicado ao vivo?','Por ENVIO (aux/FX send): um canal de efeito recebe sends de vários canais e retorna na mix — não é inserido.',3,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000503','Inserido em cada canal',false,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000503','Por envio (aux/FX send) para um canal de efeito',true,2);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000503','No cabo de força',false,3);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000503','No fader master apenas',false,4);
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('e6b50000-b551-4c00-9000-000000000504','e6b50000-b551-4c00-9000-0000000c0005','Vantagem de usar envio em vez de inserção:','Um só reverb serve vários canais e você dosa por canal (mais na voz, menos na backing, nada no bumbo).',4,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000504','Gasta mais processamento',false,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000504','Um efeito serve vários canais, dosado por canal',true,2);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000504','Corta o grave',false,3);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000504','Aumenta o ganho',false,4);
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('e6b50000-b551-4c00-9000-000000000505','e6b50000-b551-4c00-9000-0000000c0005','Bom gosto com reverb na voz ao vivo:','Menos é mais — reverb demais afoga a letra e tira a inteligibilidade. Locução/palestra: seco.',5,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000505','Quanto mais, melhor',false,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000505','Com parcimônia, para não afogar a letra',true,2);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000505','Sempre no máximo no refrão',false,3);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000505','Só no bumbo',false,4);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values
  ('e6b50000-b551-4c00-9000-0000000b0006','e6b50000-b551-4c00-9000-0000000000a1','Microfonia (feedback): como evitar e combater','texto','<p><strong>Microfonia é aquele apito ou ronco que nasce quando o som da caixa volta para o microfone.</strong> É o pesadelo do técnico ao vivo — assusta o público, pode danificar equipamento e ouvido. A boa notícia: microfonia tem causa física clara e se combate com método. Nesta aula você entende por que ela acontece e as manobras para evitá-la e matá-la rápido.</p>
insert into public.quizzes (id,lesson_id,titulo) values ('e6b50000-b551-4c00-9000-0000000c0006','e6b50000-b551-4c00-9000-0000000b0006','Quiz — Microfonia (feedback)');
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('e6b50000-b551-4c00-9000-000000000601','e6b50000-b551-4c00-9000-0000000c0006','Por que a microfonia (apito) acontece?','É um laço: o som da caixa volta ao microfone, é amplificado de novo e se realimenta até apitar.',1,1);
