insert into public.ai_animations (lesson_id,tipo,status,model,roteiro,urls) values ('e6b50000-b551-4c00-9000-0000000b0006','interactive','ready','handcrafted-interactive','{"titulo":"RTA — o que é a microfonia (animado)","cenas":[{"numero":1,"titulo":"RTA — o que é a microfonia (animado)","modo":"widget","narracao":"Veja no analisador de espectro (RTA) o pico de microfonia nascer, crescer e apitar — e como o corte no EQ o derruba.","explicacao_texto":"Veja no analisador de espectro (RTA) o pico de microfonia nascer, crescer e apitar — e como o corte no EQ o derruba.","destaques":["Pico estreito numa frequência","Ganho antes da realimentação","Cortar a frequência no EQ","Demo automática em loop"]}]}'::jsonb,'[{"html":"<!doctype html>\n<html lang=\"pt-BR\">\n<head>\n<meta charset=\"utf-8\">\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1\">\n<title>RTA — O que é microfonia (SMU)</title>\n<style>\n  :root{--bg:#0b0f17;--panel:#151b28;--line:#26344c;--ink:#e7ecf5;--muted:#8ea0bd;\n    --amber:#F59E0B;--green:#22c55e;--red:#ef4444;--cyan:#22d3ee}\n  *{box-sizing:border-box}html,body{margin:0}\n  body{background:var(--bg);color:var(--ink);font-family:\"Space Grotesk\",system-ui,-apple-system,\"Segoe UI\",Roboto,sans-serif;\n    -webkit-font-smoothing:antialiased;padding:10px;user-select:none}\n  h1{font-size:15px;margin:0 0 2px}.sub{font-size:11.5px;color:var(--muted);margin-bottom:8px}\n  .status{display:flex;gap:8px;align-items:center;background:#0c1220;border:1px solid var(--line);border-radius:10px;padding:8px 12px;margin-bottom:8px;min-height:40px}\n  .dot{width:12px;height:12px;border-radius:50%;background:var(--green);flex:0 0 auto;box-shadow:0 0 8px var(--green)}\n  .dot.bad{background:var(--red);box-shadow:0 0 12px var(--red)}\n  .status .msg{font-size:12.5px;line-height:1.25;flex:1}.status .msg b{color:var(--amber)}\n  .freq{font-size:11px;color:var(--muted);white-space:nowrap}\n  .wrap{background:linear-gradient(180deg,#0e1420,#0a0f18);border:1px solid var(--line);border-radius:12px;padding:8px}\n  canvas{width:100%;height:auto;display:block;border-radius:8px}\n  .controls{display:flex;gap:8px;flex-wrap:wrap;margin-top:8px}\n  button{font:inherit;font-size:12px;font-weight:700;padding:9px 12px;border-radius:8px;border:1px solid var(--line);\n    background:#111a2b;color:var(--ink);cursor:pointer;flex:1 1 auto;min-width:120px;touch-action:manipulation}\n  button.warn{border-color:var(--red);color:#ffd7d7}\n  button.ok{border-color:var(--green);color:#d7ffe2}\n  button.amber{border-color:var(--amber);color:#ffe6bf}\n  button:active{transform:translateY(1px)}\n  .legend{font-size:10.5px;color:var(--muted);margin-top:8px;line-height:1.35}\n  .legend b{color:var(--ink)}\n</style>\n</head>\n<body>\n  <h1>RTA — o que é a microfonia (feedback)</h1>\n  <div class=\"sub\">O analisador de espectro (RTA) mostra a energia por frequência. Veja um pico nascer, crescer e \"apitar\" — e como o EQ mata.</div>\n\n  <div class=\"status\">\n    <span class=\"dot\" id=\"dot\"></span>\n    <span class=\"msg\" id=\"msg\">Sistema estável. Suba o ganho para ver a microfonia começar.</span>\n    <span class=\"freq\" id=\"freq\"></span>\n  </div>\n\n  <div class=\"wrap\"><canvas id=\"rta\" width=\"900\" height=\"340\"></canvas></div>\n\n  <div class=\"controls\">\n    <button id=\"bGain\" class=\"amber\">▲ Subir ganho</button>\n    <button id=\"bFeed\" class=\"warn\">🔴 Simular microfonia</button>\n    <button id=\"bCut\" class=\"ok\">✂ Cortar a frequência (EQ)</button>\n    <button id=\"bAuto\">▶ Demo automática</button>\n  </div>\n\n  <div class=\"legend\">\n    <b>Como ler:</b> cada barra é uma faixa de frequência (graves à esquerda, agudos à direita). A microfonia é aquele\n    <b>pico estreito e altíssimo</b> numa frequência só — o som da caixa voltando ao microfone e se realimentando. Quando o\n    <b>ganho antes da realimentação</b> é ultrapassado, o pico dispara. O técnico <b>identifica a frequência</b> e a\n    <b>corta no EQ</b> (o \"✂\"), derrubando o pico sem baixar o show todo.\n</div>\n\n<script>\n\"use strict\";\n(function(){\n  const $=id=>document.getElementById(id);\n  const cv=$(\"rta\"), ctx=cv.getContext(\"2d\");\n  const N=31; // bandas 1/3 de oitava (20 Hz .. 20 kHz)\n  const centers=[20,25,31,40,50,63,80,100,125,160,200,250,315,400,500,630,800,1000,1250,1600,2000,2500,3150,4000,5000,6300,8000,10000,12500,16000,20000];\n  const fLabel=i=>{const f=centers[i];return f>=1000?(f/1000)+\"k\":f+\"\";};\n  const FB=21; // índice da frequência que realimenta (~2.5 kHz), típico de microfonia de voz\n  // espectro base tipo voz (dB relativos)\n  const base=centers.map((f)=>{\n    let v=0.42;\n    if(f<80)v=0.18; else if(f<250)v=0.55; else if(f<2000)v=0.6; else if(f<6000)v=0.45; else v=0.28;\n    return v;\n  });\n  let peak=0;      // energia extra da microfonia (0..1.6)\n  let gain=0;      // \"ganho\" acima do limiar (0..1)\n  const THR=0.62;  // limiar de gain-before-feedback\n  let ringPhase=0;\n  let auto=false, autoT=0, autoStage=0;\n\n  function setStatus(bad,msg,f){ $(\"dot\").className=\"dot\"+(bad?\" bad\":\"\"); $(\"msg\").innerHTML=msg; $(\"freq\").textContent=f||\"\"; }\n\n  function draw(){\n    const W=cv.width,H=cv.height, pad=26, bw=(W-pad*2)/N;\n    ctx.clearRect(0,0,W,H);\n    // grade\n    ctx.strokeStyle=\"rgba(255,255,255,.05)\"; ctx.lineWidth=1;\n    for(let g=0;g<=4;g++){const y=pad+(H-pad*2)*g/4;ctx.beginPath();ctx.moveTo(pad,y);ctx.lineTo(W-pad,y);ctx.stroke();}\n    // barras\n    ringPhase+=0.35;\n    for(let i=0;i<N;i++){\n      let v=base[i];\n      if(i===FB){ v += peak*(0.9+0.1*Math.sin(ringPhase)); }\n      else { v += Math.max(0,peak-0.6)*Math.exp(-Math.abs(i-FB)/2.2)*0.4; } // vizinhança sobe um pouco\n      v=Math.max(0,Math.min(1.15,v));\n      const x=pad+i*bw+1, h=(H-pad*2)*(v/1.15), y=(H-pad)-h;\n      const danger=(i===FB && peak>0.5);\n      const grd=ctx.createLinearGradient(0,y,0,H-pad);\n      if(danger){grd.addColorStop(0,\"#ff5b5b\");grd.addColorStop(1,\"#7a1616\");}\n      else{grd.addColorStop(0,\"#38d9c6\");grd.addColorStop(.6,\"#22a58f\");grd.addColorStop(1,\"#0f5a4e\");}\n      ctx.fillStyle=grd; ctx.fillRect(x,y,bw-2,h);\n      if(danger){ ctx.fillStyle=\"rgba(255,80,80,\"+(0.25+0.2*Math.sin(ringPhase))+\")\"; ctx.fillRect(x-1,pad,bw,H-pad*2); }\n    }\n    // rótulos de eixo (algumas frequências)\n    ctx.fillStyle=\"rgba(180,200,225,.55)\"; ctx.font=\"10px system-ui\"; ctx.textAlign=\"center\";\n    [0,6,11,17,21,24,27,30].forEach(i=>{ctx.fillText(fLabel(i),pad+i*bw+bw/2,H-8);});\n    // marcador da microfonia\n    if(peak>0.5){\n      const x=pad+FB*bw+bw/2;\n      ctx.strokeStyle=\"rgba(255,90,90,.8)\";ctx.setLineDash([4,4]);ctx.beginPath();ctx.moveTo(x,pad);ctx.lineTo(x,H-pad);ctx.stroke();ctx.setLineDash([]);\n      ctx.fillStyle=\"#ff6b6b\";ctx.font=\"bold 12px system-ui\";ctx.fillText(\"▲ \"+fLabel(FB)+\"Hz\",x,pad-4);\n    }\n  }\n\n  function tick(){\n    // dinâmica da realimentação: se gain passa do limiar, o pico cresce sozinho (loop)\n    if(gain>THR){ peak += (0.02+ (gain-THR)*0.06); }\n    else { peak -= 0.03; }\n    peak=Math.max(0,Math.min(1.55,peak));\n\n    if(peak>0.5){\n      setStatus(true, \"<b>MICROFONIA!</b> Um pico dispara e se realimenta sozinho — o apito. Corte a frequência no EQ.\", fLabel(FB)+\" Hz\");\n    } else if(gain>0.3){\n      setStatus(false, \"Perto do limite: ganho alto. Mais um pouco e a frequência da sala começa a apitar.\", \"\");\n    } else {\n      setStatus(false, \"Sistema estável. Suba o ganho para ver a microfonia começar.\", \"\");\n    }\n\n    if(auto){ autoT++;\n      if(autoStage===0){ gain=Math.min(1,gain+0.012); if(gain>=0.98){autoStage=1;autoT=0;} }        // sobe ganho\n      else if(autoStage===1){ if(peak>1.2 && autoT>30){autoStage=2;autoT=0;} }                        // deixa apitar\n      else if(autoStage===2){ gain=0.2; peak=Math.max(0,peak-0.08); if(peak<=0){autoStage=3;autoT=0;} } // corta (EQ)\n      else if(autoStage===3){ if(autoT>60){autoStage=0;gain=0;} }                                      // pausa e repete\n    }\n    draw(); requestAnimationFrame(tick);\n  }\n\n  $(\"bGain\").onclick=()=>{ auto=false; gain=Math.min(1,gain+0.18); };\n  $(\"bFeed\").onclick=()=>{ auto=false; gain=1; };\n  $(\"bCut\").onclick=()=>{ auto=false; gain=0.2; peak=Math.max(0,peak*0.15); setStatus(false,\"<b>Frequência cortada no EQ.</b> O pico caiu e o apito parou — sem baixar o show todo.\",\"\"); };\n  $(\"bAuto\").onclick=()=>{ auto=!auto; autoStage=0; autoT=0; gain=0; peak=0; $(\"bAuto\").textContent=auto?\"⏸ Pausar demo\":\"▶ Demo automática\"; };\n\n  // começa em demo automática para já \"animar\"\n  auto=true; $(\"bAuto\").textContent=\"⏸ Pausar demo\";\n  requestAnimationFrame(tick);\n})();\n</script>\n</body>\n</html>\n"}]'::jsonb);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values
  ('e6b50000-b551-4c00-9000-0000000b0007','e6b50000-b551-4c00-9000-0000000000a1','Acústica básica: a sala também toca','texto','<p><strong>A sala também toca.</strong> Você pode ter a melhor mesa, o melhor microfone e a melhor caixa — mas quem ouve o som é o ambiente antes do público. Paredes, teto, piso e até as pessoas mudam o que chega ao ouvido. Entender o básico de <strong>acústica</strong> explica por que o mesmo equipamento soa ótimo num lugar e "embolado" em outro — e o que o técnico faz a respeito.</p>
insert into public.quizzes (id,lesson_id,titulo) values ('e6b50000-b551-4c00-9000-0000000c0007','e6b50000-b551-4c00-9000-0000000b0007','Quiz — Acústica básica');
