insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values
  ('e6b50000-b551-4c00-9000-0000000b0008','e6b50000-b551-4c00-9000-0000000000a2','Microfones: tipos, phantom power e padrão polar','texto','<p><strong>O microfone é a porta de entrada do som.</strong> Escolher o microfone errado — ou usar do jeito errado — estraga tudo o que vem depois, por melhor que seja a mesa. Nesta aula você aprende os tipos, quando usar cada um, o que é phantom power e como o "padrão polar" ajuda a evitar aquele assobio horrível: a microfonia.</p>
insert into public.quizzes (id,lesson_id,titulo) values ('e6b50000-b551-4c00-9000-0000000c0008','e6b50000-b551-4c00-9000-0000000b0008','Quiz — Microfones');
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('e6b50000-b551-4c00-9000-000000000801','e6b50000-b551-4c00-9000-0000000c0008','Qual microfone é o padrão para voz ao vivo num ambiente barulhento?','O dinâmico cardioide é robusto, aguenta pressão sonora alta e rejeita o som de trás — ideal para voz ao vivo. Não precisa de phantom.',1,1);
