insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000801','Dinâmico cardioide',true,2);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000801','Lapela omnidirecional',false,3);
