insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('e6b50000-b551-4c00-9000-000000000802','e6b50000-b551-4c00-9000-0000000c0008','Um microfone condensador precisa de:','O condensador precisa de phantom power (+48V), enviado pela mesa pelo cabo XLR. Sem isso, ele não funciona.',2,1);
