insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('e6b50000-b551-4c00-9000-000000000803','e6b50000-b551-4c00-9000-0000000c0008','O que faz um padrão polar cardioide?','O cardioide capta na frente e rejeita atrás. Por isso você aponta a parte de trás (zona surda) para as caixas, evitando microfonia.',3,1);
