insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('e6b50000-b551-4c00-9000-000000000804','e6b50000-b551-4c00-9000-0000000c0008','Para evitar microfonia (feedback), o microfone deve:','O mic não deve ''olhar'' para as caixas. Aponte a zona de rejeição do padrão polar para a PA/retorno, e mantenha o ganho só o necessário.',4,1);
