insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('e6b50000-b551-4c00-9000-000000000806','e6b50000-b551-4c00-9000-0000000c0008','Dois microfones sem fio ligados no mesmo canal/frequência causam:','Interferência e cortes. Cada sistema sem fio precisa de um canal/frequência diferente para funcionar sem conflito.',6,1);
