insert into public.ai_animations (lesson_id,tipo,status,model,roteiro,urls) values ('e6b50000-b551-4c00-9000-0000000b0008','interactive','ready','handcrafted-interactive','{"titulo":"Simulador — Microfones e Padrão Polar","cenas":[{"numero":1,"titulo":"Simulador — Microfones e Padrão Polar","modo":"widget","narracao":"Escolha o microfone certo para cada situação e use o padrão polar contra microfonia. Complete as 4 missões.","explicacao_texto":"Escolha o microfone certo para cada situação e use o padrão polar contra microfonia. Complete as 4 missões.","destaques":["Dinâmico × condensador × lapela × sem fio","Phantom power +48V","Padrão polar e microfonia"]}]}'::jsonb,'[{"html":"<!doctype html>\n<html lang=\"pt-BR\">\n<head>\n<meta charset=\"utf-8\">\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1\">\n<title>Simulador — Microfones: escolha e padrão polar (SMU)</title>\n<style>\n  :root{--bg:#0b0f17;--panel:#131a29;--panel2:#0e1420;--line:#233149;--ink:#e7ecf5;\n    --muted:#8ea0bd;--amber:#F59E0B;--green:#22c55e;--red:#ef4444;--cyan:#22d3ee}\n  *{box-sizing:border-box}html,body{margin:0}\n  body{background:var(--bg);color:var(--ink);font-family:\"Space Grotesk\",system-ui,-apple-system,\"Segoe UI\",Roboto,sans-serif;\n    -webkit-font-smoothing:antialiased;padding:10px}\n  h1{font-size:15px;margin:0 0 2px}.sub{font-size:11.5px;color:var(--muted);margin-bottom:10px}\n  .mission{display:flex;gap:10px;align-items:center;background:#0c1220;border:1px solid var(--line);border-radius:10px;padding:9px 12px;margin-bottom:12px}\n  .mission .idx{font-size:10px;color:var(--amber);font-weight:800;letter-spacing:.8px;white-space:nowrap}\n  .mission .txt{font-size:12.5px;line-height:1.3;flex:1}.mission .txt b{color:var(--amber)}\n  .mission button{font:inherit;font-size:11px;color:var(--muted);background:transparent;border:1px solid var(--line);border-radius:7px;padding:6px 9px;cursor:pointer}\n  .grid{display:flex;flex-wrap:wrap;gap:12px}\n  .card{flex:1 1 320px;background:linear-gradient(180deg,var(--panel),var(--panel2));border:1px solid var(--line);border-radius:12px;padding:14px}\n  .card h3{margin:0 0 10px;font-size:11px;letter-spacing:1.2px;color:var(--muted);text-transform:uppercase}\n  .scene{font-size:13px;line-height:1.4;background:#0c1220;border:1px solid var(--line);border-radius:9px;padding:10px 12px;margin-bottom:12px}\n  .scene b{color:var(--amber)}\n  .opts{display:grid;grid-template-columns:1fr 1fr;gap:8px;margin-bottom:10px}\n  .opt{font:inherit;font-size:12px;text-align:left;padding:10px;border-radius:9px;border:1px solid var(--line);background:#0c1220;color:var(--ink);cursor:pointer;display:flex;gap:8px;align-items:center;transition:.15s}\n  .opt .em{font-size:18px}.opt.sel{border-color:var(--amber);background:#1a1608}\n  .opt.correct{border-color:var(--green);background:#0e1a10}.opt.wrong{border-color:var(--red);background:#1a1010}\n  .row{display:flex;gap:10px;align-items:center;margin:8px 0;flex-wrap:wrap}\n  .toggle{font:inherit;font-size:12px;font-weight:700;padding:9px 13px;border-radius:9px;border:1px solid var(--line);background:#0c1220;color:var(--muted);cursor:pointer}\n  .toggle.on{background:var(--green);border-color:var(--green);color:#08120a}\n  .verdict{font-size:12.5px;font-weight:700;min-height:18px;margin-top:6px}.verdict.good{color:var(--green)}.verdict.bad{color:var(--red)}\n  .btn{font:inherit;font-size:12.5px;font-weight:800;padding:10px 16px;border-radius:9px;border:0;background:var(--amber);color:#0b0f17;cursor:pointer}\n  canvas{width:100%;height:auto;display:block;background:#080d15;border:1px solid #1b2740;border-radius:10px}\n  select{font:inherit;background:#0c1220;color:var(--ink);border:1px solid var(--line);border-radius:8px;padding:8px}\n  label.sl{font-size:11px;color:var(--muted);display:block;margin-top:8px}\n  input[type=range]{width:100%;accent-color:var(--amber);height:24px}\n  .riskbar{height:12px;border-radius:6px;background:#05070d;border:1px solid #1a2540;overflow:hidden;margin-top:4px}\n  .riskbar i{display:block;height:100%;width:0%;background:linear-gradient(90deg,var(--green),var(--amber) 60%,var(--red));transition:width .1s}\n  @media(max-width:520px){.opts{grid-template-columns:1fr}}\n</style>\n</head>\n<body>\n  <h1>Microfones: escolha certa e padrão polar</h1>\n  <div class=\"sub\">Escolha o microfone para cada situação e entenda como o padrão polar evita microfonia.</div>\n  <div class=\"mission\">\n    <span class=\"idx\" id=\"mIdx\">MISSÃO 1/4</span>\n    <span class=\"txt\" id=\"mTxt\">—</span>\n    <button id=\"mSkip\">Pular</button>\n  </div>\n\n  <div class=\"grid\">\n    <!-- ESCOLHA -->\n    <div class=\"card\">\n      <h3>Situação & Escolha</h3>\n      <div class=\"scene\" id=\"scene\">—</div>\n      <div class=\"opts\" id=\"opts\"></div>\n      <div class=\"row\">\n        <button class=\"toggle\" id=\"phantom\">+48V Phantom</button>\n        <button class=\"btn\" id=\"confirm\">Confirmar</button>\n      </div>\n      <div class=\"verdict\" id=\"verdict\"></div>\n    </div>\n\n    <!-- PADRÃO POLAR -->\n    <div class=\"card\">\n      <h3>Padrão Polar & Microfonia</h3>\n      <div class=\"row\">\n        <span style=\"font-size:11px;color:var(--muted)\">Padrão:</span>\n        <select id=\"pattern\">\n          <option value=\"omni\">Omnidirecional</option>\n          <option value=\"cardioid\" selected>Cardioide</option>\n          <option value=\"super\">Supercardioide</option>\n        </select>\n      </div>\n      <canvas id=\"polar\" width=\"360\" height=\"300\"></canvas>\n      <label class=\"sl\">Direção para onde o microfone aponta: <b id=\"aimTxt\">0°</b></label>\n      <input type=\"range\" id=\"aim\" min=\"0\" max=\"359\" value=\"0\">\n      <label class=\"sl\">Risco de microfonia (feedback) da caixa de PA 🔊:</label>\n      <div class=\"riskbar\"><i id=\"risk\"></i></div>\n      <div class=\"verdict\" id=\"polarVerdict\"></div>\n    </div>\n  </div>\n\n<script>\n\"use strict\";\n(function(){\n  // ---------- ESCOLHA DE MIC ----------\n  const MICS = {\n    din:  {em:\"🎤\", nm:\"Dinâmico cardioide (de mão)\"},\n    cond: {em:\"🎙️\", nm:\"Condensador (estúdio)\"},\n    lap:  {em:\"📎\", nm:\"Lapela / Headset sem fio\"},\n    hand: {em:\"📡\", nm:\"Sem fio de mão (dinâmico)\"},\n  };\n  const scenarios=[\n    { txt:''<b>Voz principal</b> de um cantor no palco, show ao vivo e barulhento. Qual o microfone mais indicado?'',\n      opts:[\"din\",\"cond\",\"lap\",\"hand\"], correct:\"din\", phantom:false,\n      why:\"Dinâmico cardioide: robusto, aguenta pressão sonora alta e rejeita o que vem de trás — o padrão para voz ao vivo. Não precisa de phantom.\" },\n    { txt:''Gravação de um <b>vocal em estúdio</b> (ambiente silencioso, busca de detalhe e brilho). Escolha o mic e a alimentação.'',\n      opts:[\"din\",\"cond\",\"lap\",\"hand\"], correct:\"cond\", phantom:true,\n      why:\"Condensador capta mais detalhe e agudos — ideal em estúdio. Ele PRECISA de +48V (phantom power) para funcionar.\" },\n    { txt:''Um <b>palestrante que anda pelo palco</b> e precisa das mãos livres. Qual microfone?'',\n      opts:[\"din\",\"cond\",\"lap\",\"hand\"], correct:\"lap\", phantom:false,\n      why:\"Lapela ou headset sem fio deixa as mãos livres e mantém distância constante da boca — perfeito para palestra em movimento.\" },\n  ];\n  let sc=0, sel=null, phantom=false;\n  const $=id=>document.getElementById(id);\n  function renderScene(){\n    const s=scenarios[sc]; $(\"scene\").innerHTML=s.txt; sel=null; phantom=false;\n    $(\"phantom\").classList.remove(\"on\"); $(\"verdict\").textContent=\"\";\n    const o=$(\"opts\"); o.innerHTML=\"\";\n    s.opts.forEach(k=>{ const b=document.createElement(\"button\"); b.className=\"opt\"; b.dataset.k=k;\n      b.innerHTML=`<span class=\"em\">${MICS[k].em}</span> ${MICS[k].nm}`;\n      b.onclick=()=>{ sel=k; [...o.children].forEach(c=>c.classList.remove(\"sel\",\"correct\",\"wrong\")); b.classList.add(\"sel\"); };\n      o.appendChild(b); });\n  }\n  $(\"phantom\").onclick=()=>{ phantom=!phantom; $(\"phantom\").classList.toggle(\"on\",phantom); };\n  $(\"confirm\").onclick=()=>{\n    if(sel===null){ $(\"verdict\").textContent=\"Selecione um microfone primeiro.\"; $(\"verdict\").className=\"verdict bad\"; return; }\n    const s=scenarios[sc]; const okMic=sel===s.correct; const okPh=phantom===s.phantom;\n    [...$(\"opts\").children].forEach(c=>{ if(c.dataset.k===s.correct)c.classList.add(\"correct\"); else if(c.dataset.k===sel&&!okMic)c.classList.add(\"wrong\"); });\n    if(okMic&&okPh){ $(\"verdict\").innerHTML=\"✔ \"+s.why; $(\"verdict\").className=\"verdict good\"; checkMissions(true); }\n    else if(okMic&&!okPh){ $(\"verdict\").innerHTML= s.phantom? \"Quase! Este microfone precisa do <b>+48V</b> ligado.\" : \"Quase! Este microfone <b>não</b> usa phantom — desligue o +48V.\"; $(\"verdict\").className=\"verdict bad\"; }\n    else { $(\"verdict\").innerHTML=\"✖ Não é o ideal aqui. \"+s.why; $(\"verdict\").className=\"verdict bad\"; }\n  };\n\n  // ---------- POLAR ----------\n  const cv=$(\"polar\"), ctx=cv.getContext(\"2d\");\n  function gain(pattern,phi){ // phi em rad, 0 = frente\n    const c=Math.cos(phi);\n    if(pattern===\"omni\") return 1;\n    if(pattern===\"cardioid\") return 0.5+0.5*c;             // null atrás (180°)\n    return 0.375+0.625*c;                                   // supercardioide (null ~127°)\n  }\n  function drawPolar(){\n    const w=cv.width,h=cv.height,cx=w/2,cy=h/2,R=Math.min(w,h)/2-24;\n    ctx.clearRect(0,0,w,h);\n    // grid\n    ctx.strokeStyle=\"#182339\";ctx.fillStyle=\"#3a4a66\";ctx.font=\"9px system-ui\";ctx.textAlign=\"center\";\n    for(let r=0.25;r<=1;r+=0.25){ ctx.beginPath();ctx.arc(cx,cy,R*r,0,7);ctx.stroke(); }\n    ctx.beginPath();ctx.moveTo(cx-R,cy);ctx.lineTo(cx+R,cy);ctx.moveTo(cx,cy-R);ctx.lineTo(cx,cy+R);ctx.stroke();\n    const aim=(+$(\"aim\").value)*Math.PI/180;\n    const pat=$(\"pattern\").value;\n    // curva (aponta para ''aim''; 0° tela = topo)\n    ctx.beginPath();\n    for(let a=0;a<=360;a+=2){ const ang=a*Math.PI/180; const phi=ang-aim; const g=gain(pat,phi);\n      const sx=cx+Math.sin(ang)*R*g, sy=cy-Math.cos(ang)*R*g; if(a===0)ctx.moveTo(sx,sy);else ctx.lineTo(sx,sy); }\n    ctx.closePath(); ctx.fillStyle=\"rgba(245,158,11,.16)\"; ctx.fill(); ctx.strokeStyle=\"var(--amber)\"; ctx.strokeStyle=\"#F59E0B\"; ctx.lineWidth=2; ctx.stroke();\n    // seta de apontamento\n    ctx.strokeStyle=\"#22d3ee\";ctx.lineWidth=2;ctx.beginPath();ctx.moveTo(cx,cy);\n    ctx.lineTo(cx+Math.sin(aim)*R*0.5,cy-Math.cos(aim)*R*0.5);ctx.stroke();\n    ctx.fillStyle=\"#22d3ee\";ctx.font=\"700 10px system-ui\";ctx.fillText(\"frente\",cx+Math.sin(aim)*R*0.62,cy-Math.cos(aim)*R*0.62);\n    // mic no centro\n    ctx.fillStyle=\"#e7ecf5\";ctx.beginPath();ctx.arc(cx,cy,6,0,7);ctx.fill();\n    // PA fixa (fonte de microfonia) no topo-direita (45°)\n    const paAng=45*Math.PI/180; const px=cx+Math.sin(paAng)*R, py=cy-Math.cos(paAng)*R;\n    ctx.font=\"18px system-ui\";ctx.fillText(\"🔊\",px,py+6);\n    // risco = ganho do mic na direção da PA\n    const phiPA=paAng-aim; const g=gain(pat,phiPA); const risk=Math.round(g*100);\n    $(\"risk\").style.width=risk+\"%\";\n    const pv=$(\"polarVerdict\");\n    if(risk<25){ pv.textContent=\"✔ Baixo risco: a PA está na zona de rejeição do microfone.\"; pv.className=\"verdict good\"; }\n    else if(risk<60){ pv.textContent=\"Atenção: risco médio de microfonia.\"; pv.className=\"verdict bad\"; }\n    else { pv.textContent=\"✖ Alto risco de microfonia: o mic está \\\"olhando\\\" para a PA.\"; pv.className=\"verdict bad\"; }\n    return risk;\n  }\n  $(\"aim\").oninput=()=>{ $(\"aimTxt\").textContent=$(\"aim\").value+\"°\"; const r=drawPolar(); checkMissions(false,r); };\n  $(\"pattern\").onchange=()=>{ const r=drawPolar(); checkMissions(false,r); };\n\n  // ---------- MISSÕES ----------\n  const missions=[\n    { t:''Escolha o microfone para a <b>voz principal ao vivo</b> (painel da esquerda) e confirme.'', kind:\"scene\", scene:0 },\n    { t:''Agora um <b>vocal de estúdio</b>: escolha o mic certo e ligue a alimentação correta.'', kind:\"scene\", scene:1 },\n    { t:''E o <b>palestrante que anda no palco</b>? Escolha e confirme.'', kind:\"scene\", scene:2 },\n    { t:''No painel da direita: use padrão <b>cardioide</b> e gire a <b>direção do microfone</b> para deixar o risco de microfonia da PA 🔊 no verde (baixo).'', kind:\"polar\" },\n  ];\n  let mi=0;\n  function paintMission(){ const idx=$(\"mIdx\"),txt=$(\"mTxt\");\n    if(mi>=missions.length){ idx.textContent=\"CONCLUÍDO\"; txt.innerHTML=\"🎓 <b>Boa!</b> Você sabe escolher o microfone por situação e usar o padrão polar contra microfonia.\"; $(\"mSkip\").style.display=\"none\"; return; }\n    idx.textContent=\"MISSÃO \"+(mi+1)+\"/\"+missions.length; txt.innerHTML=missions[mi].t;\n    const m=missions[mi]; if(m.kind===\"scene\"){ sc=m.scene; renderScene(); } }\n  function checkMissions(sceneOk,risk){ if(mi>=missions.length)return; const m=missions[mi];\n    if(m.kind===\"scene\"&&sceneOk){ mi++; paintMission(); }\n    else if(m.kind===\"polar\"&&$(\"pattern\").value===\"cardioid\"&&(risk!==undefined?risk:drawPolar())<25){ mi++; paintMission(); } }\n  $(\"mSkip\").onclick=()=>{ if(mi<missions.length){ mi++; paintMission(); } };\n\n  // init\n  $(\"aimTxt\").textContent=\"0°\"; renderScene(); drawPolar(); paintMission();\n})();\n</script>\n</body>\n</html>\n"}]'::jsonb);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values
  ('e6b50000-b551-4c00-9000-0000000b0009','e6b50000-b551-4c00-9000-0000000000a2','Microfones sem fio: canal, frequência, sincronismo e bateria','texto','<p><strong>No corporativo, o microfone sem fio é quase obrigatório</strong> — palestrante que anda, mesa-redonda, entrevista, premiação. E é também onde mais acontece vexame: microfone que corta, chia ou emudece no meio da fala. A boa notícia: quase todos esses problemas se evitam com quatro cuidados simples. Vamos a eles.</p>
insert into public.quizzes (id,lesson_id,titulo) values ('e6b50000-b551-4c00-9000-0000000c0009','e6b50000-b551-4c00-9000-0000000b0009','Quiz — Microfones sem fio');
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('e6b50000-b551-4c00-9000-000000000901','e6b50000-b551-4c00-9000-0000000c0009','Se você usa três microfones sem fio ao mesmo tempo, eles devem estar em:','Cada sistema precisa de um canal/frequência diferente. Dois no mesmo canal geram interferência e cortes.',1,1);
