insert into public.ai_animations (lesson_id,tipo,status,model,roteiro,urls) values ('e6b50000-b551-4c00-9000-0000000b0009','interactive','ready','handcrafted-interactive','{"titulo":"Simulador — Microfone sem fio","cenas":[{"numero":1,"titulo":"Simulador — Microfone sem fio","modo":"widget","narracao":"Ligue o sistema, ache um canal livre com SCAN, sincronize e cuide da bateria. Complete as 4 missões.","explicacao_texto":"Ligue o sistema, ache um canal livre com SCAN, sincronize e cuide da bateria. Complete as 4 missões.","destaques":["Canal/frequência por microfone","SCAN contra interferência","SYNC transmissor↔receptor","Bateria e dropout"]}]}'::jsonb,'[{"html":"<!doctype html>\n<html lang=\"pt-BR\">\n<head>\n<meta charset=\"utf-8\">\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1\">\n<title>Simulador — Microfone sem fio (SMU)</title>\n<style>\n  :root{--bg:#0b0f17;--panel:#151b28;--panel2:#0f1420;--line:#26344c;--ink:#e7ecf5;\n    --muted:#8ea0bd;--amber:#F59E0B;--green:#22c55e;--red:#ef4444;--cyan:#22d3ee}\n  *{box-sizing:border-box}html,body{margin:0}\n  body{background:var(--bg);color:var(--ink);font-family:\"Space Grotesk\",system-ui,-apple-system,\"Segoe UI\",Roboto,sans-serif;\n    -webkit-font-smoothing:antialiased;padding:10px;user-select:none}\n  h1{font-size:15px;margin:0 0 2px}.sub{font-size:11.5px;color:var(--muted);margin-bottom:10px}\n  .mission{display:flex;gap:10px;align-items:center;background:#0c1220;border:1px solid var(--line);border-radius:10px;padding:9px 12px;margin-bottom:12px}\n  .mission .idx{font-size:10px;color:var(--amber);font-weight:800;letter-spacing:.8px;white-space:nowrap}\n  .mission .txt{font-size:12.5px;line-height:1.3;flex:1}.mission .txt b{color:var(--amber)}\n  .mission button{font:inherit;font-size:11px;color:var(--muted);background:transparent;border:1px solid var(--line);border-radius:7px;padding:6px 9px;cursor:pointer}\n  .grid{display:flex;flex-wrap:wrap;gap:12px}\n  .card{flex:1 1 300px;background:linear-gradient(180deg,var(--panel),var(--panel2));border:1px solid var(--line);border-radius:12px;padding:14px}\n  .card h3{margin:0 0 10px;font-size:11px;letter-spacing:1.2px;color:var(--muted);text-transform:uppercase}\n  .lcd{background:#08130d;border:1px solid #16351f;border-radius:8px;padding:10px 12px;font-family:\"Courier New\",monospace;margin-bottom:10px}\n  .lcd .big{font-size:22px;font-weight:700;color:#39ff9e;letter-spacing:1px}\n  .lcd .lbl{font-size:10px;color:#4a8f6a}\n  .bars{display:flex;gap:3px;align-items:flex-end;height:22px;margin-top:4px}\n  .bars i{width:6px;background:#16351f;border-radius:1px}.bars i.on{background:#39ff9e}\n  .bars.rf i.on{background:var(--cyan)}\n  .row{display:flex;gap:8px;flex-wrap:wrap;align-items:center;margin-top:6px}\n  .chgrid{display:grid;grid-template-columns:repeat(4,1fr);gap:6px;margin:8px 0}\n  .ch{font:inherit;font-size:11px;font-weight:700;padding:8px 4px;border-radius:7px;border:1px solid var(--line);background:#0c1220;color:var(--ink);cursor:pointer;text-align:center;position:relative}\n  .ch.busy{color:var(--red);border-color:#5b2626}\n  .ch.free{color:var(--green)}\n  .ch.sel{outline:2px solid var(--amber);outline-offset:1px}\n  .ch small{display:block;font-size:8px;color:var(--muted);font-weight:600}\n  .btn{font:inherit;font-size:12px;font-weight:800;padding:9px 14px;border-radius:9px;border:0;background:var(--amber);color:#0b0f17;cursor:pointer}\n  .btn.sec{background:#0c1220;border:1px solid var(--line);color:var(--ink)}\n  .batt{display:flex;align-items:center;gap:8px;margin-top:6px}\n  .battbar{flex:1;height:14px;border-radius:4px;background:#05070d;border:1px solid #1a2540;overflow:hidden}\n  .battbar i{display:block;height:100%;background:var(--green);transition:width .2s}\n  .txbody{display:flex;flex-direction:column;align-items:center;gap:8px}\n  .mic{font-size:44px}\n  .verdict{font-size:12px;font-weight:700;min-height:16px;margin-top:8px;text-align:center}.verdict.good{color:var(--green)}.verdict.bad{color:var(--red)}\n  .tag{font-size:10px;padding:3px 8px;border-radius:20px;border:1px solid var(--line);color:var(--muted)}\n  .tag.ok{color:var(--green);border-color:var(--green)}.tag.bad{color:var(--red);border-color:var(--red)}\n</style>\n</head>\n<body>\n  <h1>Microfone sem fio — configuração</h1>\n  <div class=\"sub\">Ligue o sistema, ache um canal livre de interferência, sincronize e cuide da bateria.</div>\n  <div class=\"mission\">\n    <span class=\"idx\" id=\"mIdx\">MISSÃO 1/4</span>\n    <span class=\"txt\" id=\"mTxt\">—</span>\n    <button id=\"mSkip\">Pular</button>\n  </div>\n\n  <div class=\"grid\">\n    <!-- RECEPTOR -->\n    <div class=\"card\">\n      <h3>Receptor (na mesa)</h3>\n      <div class=\"lcd\">\n        <div class=\"lbl\">CANAL / FREQUÊNCIA</div>\n        <div class=\"big\" id=\"rxDisp\">CH— · ---.--- MHz</div>\n        <div class=\"lbl\" style=\"margin-top:6px\">RF (sinal de rádio)</div>\n        <div class=\"bars rf\" id=\"rfBars\"></div>\n        <div class=\"lbl\" style=\"margin-top:6px\">AF (áudio)</div>\n        <div class=\"bars\" id=\"afBars\"></div>\n      </div>\n      <div class=\"lbl\" style=\"font-size:10px;color:var(--muted)\">Toque num canal (verde = livre, vermelho = interferência):</div>\n      <div class=\"chgrid\" id=\"chgrid\"></div>\n      <div class=\"row\">\n        <button class=\"btn sec\" id=\"scanBtn\">🔎 SCAN (achar canal livre)</button>\n        <button class=\"btn\" id=\"syncBtn\">⇄ SYNC transmissor</button>\n      </div>\n      <div class=\"row\"><span class=\"tag\" id=\"syncTag\">não sincronizado</span></div>\n    </div>\n\n    <!-- TRANSMISSOR -->\n    <div class=\"card\" style=\"flex:1 1 220px\">\n      <h3>Transmissor (o microfone)</h3>\n      <div class=\"txbody\">\n        <div class=\"mic\" id=\"micIco\">🎤</div>\n        <button class=\"btn\" id=\"txPower\">Ligar transmissor</button>\n        <div class=\"lcd\" style=\"width:100%;text-align:center\">\n          <div class=\"lbl\">CANAL DO TX</div><div class=\"big\" id=\"txDisp\" style=\"font-size:18px\">CH—</div>\n        </div>\n        <div style=\"width:100%\">\n          <div class=\"lbl\" style=\"font-size:10px;color:var(--muted)\">Bateria</div>\n          <div class=\"batt\"><div class=\"battbar\"><i id=\"battFill\"></i></div><span id=\"battTxt\" style=\"font-size:11px\">15%</span></div>\n          <button class=\"btn sec\" id=\"battBtn\" style=\"margin-top:6px;width:100%\">🔋 Trocar / recarregar bateria</button>\n        </div>\n      </div>\n    </div>\n  </div>\n  <div class=\"verdict\" id=\"verdict\"></div>\n\n<script>\n\"use strict\";\n(function(){\n  const $=id=>document.getElementById(id);\n  // canais: alguns com interferência\n  const CH=[\n    {n:1,f:\"512.100\",busy:true},{n:2,f:\"514.375\",busy:false},{n:3,f:\"518.900\",busy:true},{n:4,f:\"521.250\",busy:false},\n    {n:5,f:\"524.600\",busy:false},{n:6,f:\"527.125\",busy:true},{n:7,f:\"530.800\",busy:false},{n:8,f:\"533.400\",busy:true},\n  ];\n  const state={ rx:1, tx:3, txOn:false, batt:15 };\n  const rxCh=()=>CH.find(c=>c.n===state.rx);\n  const synced=()=>state.tx===state.rx;\n  const receiving=()=>state.txOn && synced() && !rxCh().busy && state.batt>5;\n\n  function renderChannels(){\n    const g=$(\"chgrid\");g.innerHTML=\"\";\n    CH.forEach(c=>{ const b=document.createElement(\"button\");\n      b.className=\"ch \"+(c.busy?\"busy\":\"free\")+(c.n===state.rx?\" sel\":\"\");\n      b.innerHTML=`CH${c.n}<small>${c.busy?\"interfer.\":\"livre\"}</small>`;\n      b.onclick=()=>{state.rx=c.n;update();check();};\n      g.appendChild(b); });\n  }\n  function bars(el,n,cls){ el.innerHTML=\"\"; for(let i=0;i<10;i++){ const b=document.createElement(\"i\");\n    b.style.height=(6+i*1.6)+\"px\"; if(i<n)b.className=\"on\"; el.appendChild(b); } }\n  function update(){\n    const c=rxCh();\n    $(\"rxDisp\").textContent=\"CH\"+c.n+\" · \"+c.f+\" MHz\";\n    $(\"txDisp\").textContent=\"CH\"+state.tx;\n    $(\"txPower\").textContent=state.txOn?\"Desligar transmissor\":\"Ligar transmissor\";\n    $(\"txPower\").classList.toggle(\"sec\",state.txOn);\n    $(\"micIco\").style.opacity=state.txOn?\"1\":\"0.4\";\n    $(\"syncTag\").textContent=synced()?\"sincronizado ✓\":\"não sincronizado\";\n    $(\"syncTag\").className=\"tag \"+(synced()?\"ok\":\"bad\");\n    $(\"battFill\").style.width=state.batt+\"%\";\n    $(\"battFill\").style.background=state.batt<20?\"var(--red)\":state.batt<50?\"var(--amber)\":\"var(--green)\";\n    $(\"battTxt\").textContent=state.batt+\"%\";\n    // RF\n    let rf=0; if(state.txOn && state.batt>5){ rf = synced()? (rxCh().busy?3:9) : 1; if(!synced())rf=Math.max(rf,2); }\n    bars($(\"rfBars\"),rf,\"rf\");\n    // AF\n    bars($(\"afBars\"), receiving()? 7:0);\n    renderChannels();\n  }\n  $(\"scanBtn\").onclick=()=>{ const free=CH.find(c=>!c.busy); if(free){state.rx=free.n; $(\"verdict\").textContent=\"SCAN: canal livre encontrado — CH\"+free.n; $(\"verdict\").className=\"verdict good\";} update();check(); };\n  $(\"syncBtn\").onclick=()=>{ state.tx=state.rx; $(\"verdict\").textContent=\"Transmissor sincronizado no CH\"+state.tx; $(\"verdict\").className=\"verdict good\"; update();check(); };\n  $(\"txPower\").onclick=()=>{ state.txOn=!state.txOn; update();check(); };\n  $(\"battBtn\").onclick=()=>{ state.batt=100; $(\"verdict\").textContent=\"Bateria nova instalada (100%).\"; $(\"verdict\").className=\"verdict good\"; update();check(); };\n\n  // bateria drenando devagar quando ligado\n  setInterval(()=>{ if(state.txOn&&state.batt>0){ state.batt=Math.max(0,state.batt-1); update(); } },5000);\n\n  const M=[\n    { t:''Ligue o <b>transmissor</b> (o microfone). Veja o RF aparecer no receptor.'', ok:()=>state.txOn },\n    { t:''O canal do receptor tem <b>interferência</b> (vermelho). Clique <b>SCAN</b> para achar um canal livre (verde).'', ok:()=>!rxCh().busy },\n    { t:''Agora <b>sincronize</b> o transmissor com o receptor (mesmo canal). Clique <b>SYNC</b>.'', ok:()=>synced()&&!rxCh().busy },\n    { t:''A <b>bateria</b> está fraca. Troque/recarregue para o microfone não falhar no meio do evento.'', ok:()=>state.batt>=80&&receiving() },\n  ];\n  let mi=0;\n  function paintM(){const idx=$(\"mIdx\"),txt=$(\"mTxt\");\n    if(mi>=M.length){idx.textContent=\"CONCLUÍDO\";txt.innerHTML=\"🎓 <b>Perfeito!</b> Sistema sem fio no ar: canal livre, sincronizado e bateria cheia — sem sustos no evento.\";$(\"mSkip\").style.display=\"none\";return;}\n    idx.textContent=\"MISSÃO \"+(mi+1)+\"/\"+M.length;txt.innerHTML=M[mi].t;}\n  function check(){if(mi>=M.length)return;try{if(M[mi].ok()){mi++;paintM();}}catch(e){}}\n  $(\"mSkip\").onclick=()=>{if(mi<M.length){mi++;paintM();}};\n\n  update();paintM();\n})();\n</script>\n</body>\n</html>\n"}]'::jsonb);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values
  ('e6b50000-b551-4c00-9000-0000000b0010','e6b50000-b551-4c00-9000-0000000000a2','A mesa analógica: canais, ganho e EQ de 3 bandas (notebook via P2→P10)','texto','<p><strong>Esta é a mesa que você mais vai usar no corporativo.</strong> Palestra, treinamento, casamento, culto, festa de menor porte — quase sempre tem uma mesa analógica pequena (4, 8, 12 canais) com <strong>EQ de 3 bandas</strong> por canal. Se você entende um canal dela, entende todos os outros, porque todos são iguais. Vamos destrinchar o canal de cima para baixo.</p>
