insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('e6b50000-b551-4c00-9000-000000000a01','e6b50000-b551-4c00-9000-0000000c0010','Para ligar a saída de som de um notebook na mesa, o cabo correto costuma ser:','A saída de fone do notebook é P2 (3,5 mm); a entrada de linha estéreo da mesa é P10. Logo, cabo P2 → P10 estéreo.',1,1);
