insert into public.ai_animations (lesson_id,tipo,status,model,roteiro,urls) values ('e6b50000-b551-4c00-9000-0000000b0010','interactive','ready','handcrafted-interactive','{"titulo":"Simulador — Mesa Analógica (EQ 3 bandas)","cenas":[{"numero":1,"titulo":"Simulador — Mesa Analógica (EQ 3 bandas)","modo":"widget","narracao":"Opere uma mesa analógica de corporativo: notebook via P2→P10, ganho sem clip, EQ de 3 bandas e retorno. Complete as 5 missões.","explicacao_texto":"Opere uma mesa analógica de corporativo: notebook via P2→P10, ganho sem clip, EQ de 3 bandas e retorno. Complete as 5 missões.","destaques":["Notebook via cabo P2→P10 estéreo","Ganho sem estourar (PEAK)","EQ de 3 bandas por canal","AUX/retorno do palestrante"]}]}'::jsonb,'[{"html":"<!doctype html>\n<html lang=\"pt-BR\">\n<head>\n<meta charset=\"utf-8\">\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1\">\n<title>Simulador — Mesa Analógica (EQ 3 bandas) — SMU</title>\n<style>\n  :root{--bg:#0b0f17;--panel:#151b28;--panel2:#0f1420;--line:#26344c;--ink:#e7ecf5;\n    --muted:#8ea0bd;--amber:#F59E0B;--green:#22c55e;--red:#ef4444;--cyan:#22d3ee;--strip:#121a29}\n  *{box-sizing:border-box}html,body{margin:0}\n  body{background:var(--bg);color:var(--ink);font-family:\"Space Grotesk\",system-ui,-apple-system,\"Segoe UI\",Roboto,sans-serif;\n    -webkit-font-smoothing:antialiased;padding:10px;user-select:none}\n  h1{font-size:15px;margin:0 0 2px}.sub{font-size:11.5px;color:var(--muted);margin-bottom:10px}\n  .mission{display:flex;gap:10px;align-items:center;background:#0c1220;border:1px solid var(--line);border-radius:10px;padding:9px 12px;margin-bottom:10px}\n  .mission .idx{font-size:10px;color:var(--amber);font-weight:800;letter-spacing:.8px;white-space:nowrap}\n  .mission .txt{font-size:12.5px;line-height:1.3;flex:1}.mission .txt b{color:var(--amber)}\n  .mission button{font:inherit;font-size:11px;color:var(--muted);background:transparent;border:1px solid var(--line);border-radius:7px;padding:6px 9px;cursor:pointer}\n\n  .src{display:flex;gap:8px;align-items:center;background:#0c1220;border:1px solid var(--line);border-radius:10px;padding:8px 10px;margin-bottom:10px;flex-wrap:wrap}\n  .src .item{display:flex;gap:6px;align-items:center;font-size:11.5px;color:var(--muted)}\n  .src .plug{font:inherit;font-size:11px;font-weight:700;padding:6px 10px;border-radius:7px;border:1px solid var(--line);background:#111a2b;color:var(--ink);cursor:pointer}\n  .src .plug.done{background:var(--green);border-color:var(--green);color:#08120a}\n\n  .board{display:flex;gap:8px;overflow-x:auto;padding:10px;background:linear-gradient(180deg,#0e1420,#0a0f18);border:1px solid var(--line);border-radius:12px}\n  .strip{flex:0 0 118px;background:linear-gradient(180deg,var(--strip),#0e1524);border:1px solid var(--line);border-radius:10px;padding:9px 7px;display:flex;flex-direction:column;align-items:center;gap:7px}\n  .strip.master{flex-basis:104px;background:linear-gradient(180deg,#1b2233,#0e1524);border-color:#3a4a66}\n  .lbl{font-size:11px;font-weight:700;text-align:center;line-height:1.1}\n  .sub2{font-size:9px;color:var(--muted);text-align:center;margin-top:-4px}\n  .jack{font-size:9px;padding:2px 6px;border-radius:20px;border:1px solid var(--line);color:var(--muted)}\n  .jack.on{color:var(--green);border-color:var(--green)}\n  .knob{display:flex;flex-direction:column;align-items:center;gap:2px}\n  .dial{width:40px;height:40px;border-radius:50%;position:relative;cursor:ns-resize;touch-action:none;\n    background:radial-gradient(circle at 50% 32%,#33415f,#151d2e 72%);border:1px solid #3a4d70;box-shadow:inset 0 2px 5px #0008}\n  .dial::after{content:\"\";position:absolute;left:50%;top:4px;width:2.5px;height:14px;border-radius:2px;background:var(--amber);\n    transform-origin:50% 16px;transform:translateX(-50%) rotate(var(--rot,0deg))}\n  .dial.eq::after{background:var(--cyan)}\n  .kl{font-size:8.5px;color:var(--muted);letter-spacing:.3px}.kv{font-size:9px;font-weight:700}\n  .eqrow{display:flex;gap:5px}\n  .peak{font-size:8px;font-weight:800;color:#3a4a66;letter-spacing:.5px}.peak.on{color:var(--red)}\n  .onbtn{font:inherit;font-size:9.5px;font-weight:800;padding:4px 0;width:100%;border-radius:6px;border:1px solid var(--line);background:#0c1220;color:var(--muted);cursor:pointer}\n  .onbtn.on{background:var(--green);border-color:var(--green);color:#08120a}\n  .faderwrap{display:flex;gap:5px;height:120px;align-items:stretch}\n  .meter{width:7px;border-radius:3px;background:#05070d;border:1px solid #1a2540;position:relative;overflow:hidden}\n  .meter i{position:absolute;left:0;right:0;bottom:0;height:0%;background:linear-gradient(0deg,var(--green),var(--green) 62%,var(--amber) 84%,var(--red))}\n  .fader{width:26px;position:relative;background:linear-gradient(90deg,#0a0e17,#0d1220,#0a0e17);border-radius:5px;border:1px solid #1a2540;cursor:ns-resize;touch-action:none}\n  .fader .unity{position:absolute;left:0;right:0;top:26%;height:1px;background:#3a4d70}\n  .cap{position:absolute;left:-4px;right:-4px;height:20px;border-radius:4px;background:linear-gradient(180deg,#e9edf5,#a7b3c9 46%,#59647e 54%,#8493ad);border:1px solid #0006;box-shadow:0 2px 4px #0009;cursor:grab}\n  .cap::after{content:\"\";position:absolute;left:3px;right:3px;top:50%;height:2px;transform:translateY(-50%);background:#0b0f17;border-radius:2px}\n  .fdb{font-size:9px;color:var(--muted);font-weight:700}\n  .phantom{font:inherit;font-size:9.5px;font-weight:800;padding:5px 6px;border-radius:6px;border:1px solid var(--line);background:#0c1220;color:var(--muted);cursor:pointer;width:100%}\n  .phantom.on{background:var(--red);border-color:var(--red);color:#fff}\n  .verdict{font-size:12px;font-weight:700;min-height:16px;margin-top:8px;text-align:center}.verdict.good{color:var(--green)}.verdict.bad{color:var(--red)}\n  .hint{font-size:10px;color:var(--muted);margin-top:6px;text-align:center}\n</style>\n</head>\n<body>\n  <h1>Mesa Analógica de Som — EQ de 3 bandas</h1>\n  <div class=\"sub\">A mesa do dia a dia do corporativo: microfones, notebook (P2→P10), EQ de 3 bandas, retorno e master.</div>\n\n  <div class=\"mission\">\n    <span class=\"idx\" id=\"mIdx\">MISSÃO 1/5</span>\n    <span class=\"txt\" id=\"mTxt\">—</span>\n    <button id=\"mSkip\">Pular</button>\n  </div>\n\n  <div class=\"src\">\n    <div class=\"item\">🎤 Microfone com fio</div>\n    <div class=\"item\">📡 Mic sem fio (receptor)</div>\n    <div class=\"item\">💻 Notebook (saída de fone P2)</div>\n    <button class=\"plug\" id=\"plugNb\">Conectar notebook — cabo P2 → P10 estéreo</button>\n    <span class=\"hint\" id=\"plugHint\" style=\"margin:0\">a saída de fone (P2) do notebook vai na entrada de linha estéreo (P10) da mesa</span>\n  </div>\n\n  <div class=\"board\" id=\"board\"></div>\n  <div class=\"verdict\" id=\"verdict\"></div>\n\n<script>\n\"use strict\";\n(function(){\n  const $=id=>document.getElementById(id);\n  const clamp=(v,a,b)=>Math.max(a,Math.min(b,v));\n  // canais\n  const CH=[\n    {id:\"c1\",nm:\"Mic 1\",sub:\"XLR • voz\",kind:\"mic\",jack:\"XLR\",conn:true,  gain:35,hi:0,mid:0,lo:0,aux:0,on:true,fader:0,peak:false},\n    {id:\"c2\",nm:\"Sem fio\",sub:\"XLR • mão\",kind:\"mic\",jack:\"XLR\",conn:true, gain:30,hi:0,mid:0,lo:0,aux:0,on:true,fader:0,peak:false},\n    {id:\"ln\",nm:\"Notebook\",sub:\"Linha estéreo P10\",kind:\"line\",jack:\"P10\", conn:false,gain:50,hi:0,mid:0,lo:0,aux:0,on:true,fader:0,peak:false},\n  ];\n  const master={fader:60,phantom:false};\n  const by=id=>CH.find(c=>c.id===id);\n\n  const KN={gain:{min:0,max:100},hi:{min:-15,max:15},mid:{min:-15,max:15},lo:{min:-15,max:15},aux:{min:0,max:100}};\n  function rotOf(k,v){const d=KN[k];return -140+(v-d.min)/(d.max-d.min)*280;}\n  function kv(k,v){ if(k===\"gain\"||k===\"aux\")return Math.round(v); return (v>0?\"+\":\"\")+Math.round(v); }\n\n  const board=$(\"board\");\n  function render(){\n    board.innerHTML=\"\";\n    CH.forEach(c=>board.appendChild(stripEl(c)));\n    board.appendChild(masterEl());\n    paintClipAndRot();\n  }\n  function knob(c,k,cls){ return `<div class=\"knob\"><div class=\"dial ${cls||''''}\" data-ch=\"${c.id}\" data-k=\"${k}\"></div>\n    <div class=\"kl\">${({gain:\"GANHO\",hi:\"HIGH\",mid:\"MID\",lo:\"LOW\",aux:\"AUX\"})[k]}</div><div class=\"kv\" id=\"v-${c.id}-${k}\">${kv(k,c[k])}</div></div>`; }\n  function stripEl(c){\n    const d=document.createElement(\"div\");d.className=\"strip\";d.dataset.ch=c.id;\n    d.innerHTML=`\n      <div class=\"lbl\">${c.nm}</div><div class=\"sub2\">${c.sub}</div>\n      <span class=\"jack ${c.conn?''on'':''''}\" id=\"jack-${c.id}\">${c.conn?''● ''+c.jack:''○ sem cabo''}</span>\n      ${knob(c,\"gain\")}\n      <div class=\"eqrow\">${knob(c,\"hi\",\"eq\")}${knob(c,\"lo\",\"eq\")}</div>\n      ${knob(c,\"mid\",\"eq\")}\n      ${knob(c,\"aux\")}\n      <div class=\"peak\" id=\"peak-${c.id}\">● PEAK</div>\n      <button class=\"onbtn ${c.on?''on'':''''}\" data-on=\"${c.id}\">${c.on?''ON'':''MUTE''}</button>\n      <div class=\"faderwrap\"><div class=\"meter\"><i id=\"m-${c.id}\"></i></div>\n        <div class=\"fader\" data-fch=\"${c.id}\"><div class=\"unity\"></div><div class=\"cap\" id=\"cap-${c.id}\"></div></div></div>\n      <div class=\"fdb\" id=\"fdb-${c.id}\">${c.fader}</div>`;\n    return d;\n  }\n  function masterEl(){\n    const d=document.createElement(\"div\");d.className=\"strip master\";\n    d.innerHTML=`<div class=\"lbl\">MASTER</div><div class=\"sub2\">saída principal</div>\n      <button class=\"phantom ${master.phantom?''on'':''''}\" id=\"phantom\">+48V ${master.phantom?''ON'':''OFF''}</button>\n      <div style=\"flex:1\"></div>\n      <div class=\"faderwrap\"><div class=\"meter\"><i id=\"m-main\"></i></div><div class=\"meter\"><i id=\"m-main2\"></i></div>\n        <div class=\"fader\" data-fch=\"main\"><div class=\"unity\"></div><div class=\"cap\" id=\"cap-main\"></div></div></div>\n      <div class=\"fdb\" id=\"fdb-main\">${master.fader}</div>`;\n    return d;\n  }\n\n  // Interação unificada (mouse + toque) via Pointer Events + delegação no board.\n  // Registrada UMA vez — não re-registra a cada render (sem vazamento de listeners).\n  let knobDrag=null,faderDrag=null,lastY=0;\n  function setFaderFromY(id,y){const f=board.querySelector(''.fader[data-fch=\"''+id+''\"]'');if(!f)return;\n    const r=f.getBoundingClientRect();let v=Math.round(clamp(1-(y-r.top)/r.height,0,1)*100);\n    if(id===\"main\"){master.fader=v;$(\"fdb-main\").textContent=v;} else {const c=by(id);c.fader=v;$(\"fdb-\"+id).textContent=v;}\n    placeCap(id);check();}\n  function setupInteraction(){\n    board.addEventListener(\"pointerdown\",e=>{\n      const dial=e.target.closest(\".dial\");\n      if(dial){knobDrag={el:dial,ch:dial.dataset.ch,k:dial.dataset.k};lastY=e.clientY;board.setPointerCapture(e.pointerId);e.preventDefault();return;}\n      const f=e.target.closest(\".fader\");\n      if(f){faderDrag=f.dataset.fch;board.setPointerCapture(e.pointerId);setFaderFromY(faderDrag,e.clientY);e.preventDefault();return;}\n    });\n    board.addEventListener(\"pointermove\",e=>{\n      if(knobDrag){const dy=lastY-e.clientY;lastY=e.clientY;const c=by(knobDrag.ch),d=KN[knobDrag.k];\n        c[knobDrag.k]=clamp(c[knobDrag.k]+dy*(d.max-d.min)/150,d.min,d.max);\n        const v=$(\"v-\"+knobDrag.ch+\"-\"+knobDrag.k);if(v)v.textContent=kv(knobDrag.k,c[knobDrag.k]);\n        knobDrag.el.style.setProperty(\"--rot\",rotOf(knobDrag.k,c[knobDrag.k])+\"deg\");checkClip(c);check();e.preventDefault();}\n      else if(faderDrag){setFaderFromY(faderDrag,e.clientY);e.preventDefault();}\n    });\n    const end=()=>{knobDrag=null;faderDrag=null;};\n    board.addEventListener(\"pointerup\",end);board.addEventListener(\"pointercancel\",end);\n    // botões (delegação) — funcionam mesmo após re-render\n    board.addEventListener(\"click\",e=>{\n      const on=e.target.closest(\"[data-on]\");if(on){const c=by(on.dataset.on);c.on=!c.on;render();check();return;}\n      const ph=e.target.closest(\"#phantom\");if(ph){master.phantom=!master.phantom;render();check();return;}\n    });\n  }\n  function placeCap(id){ const v=id===\"main\"?master.fader:by(id).fader; const cap=$(\"cap-\"+id); if(cap)cap.style.bottom=\"calc(\"+v+\"% - 10px)\"; }\n  function paintClipAndRot(){ CH.forEach(c=>{ [\"gain\",\"hi\",\"mid\",\"lo\",\"aux\"].forEach(k=>{const el=board.querySelector(''.dial[data-ch=\"''+c.id+''\"][data-k=\"''+k+''\"]'');if(el)el.style.setProperty(\"--rot\",rotOf(k,c[k])+\"deg\");}); placeCap(c.id); checkClip(c); }); placeCap(\"main\"); }\n  function checkClip(c){ c.peak = c.conn && c.on && c.kind===\"mic\" && c.gain>72; const el=$(\"peak-\"+c.id); if(el)el.classList.toggle(\"on\",c.peak); }\n\n  // notebook connect\n  $(\"plugNb\").onclick=()=>{ const ln=by(\"ln\"); ln.conn=!ln.conn; $(\"plugNb\").classList.toggle(\"done\",ln.conn);\n    $(\"plugNb\").textContent = ln.conn? \"✔ Notebook conectado (P2→P10)\" : \"Conectar notebook — cabo P2 → P10 estéreo\";\n    render(); check(); };\n\n  // meters loop\n  let t=0;\n  function loop(){ t+=0.05;\n    CH.forEach(c=>{ const el=$(\"m-\"+c.id); if(!el)return;\n      let lvl=0; if(c.conn&&c.on){ const base=c.kind===\"mic\"?(c.gain/100):(0.6); const env=0.55+0.45*Math.sin(t*(1.7)+c.id.length);\n        lvl=clamp(base*(c.fader/100)*env*1.5 + (c.peak?0.3:0),0,1); }\n      el.style.height=(lvl*100)+\"%\"; });\n    let sum=0;CH.forEach(c=>{if(c.conn&&c.on)sum+=(c.kind===\"mic\"?c.gain/100:0.6)*(c.fader/100);});\n    const main=clamp(sum*(master.fader/100)*1.1,0,1); const mm=$(\"m-main\"),mm2=$(\"m-main2\");\n    if(mm){mm.style.height=(main*100)+\"%\";} if(mm2){mm2.style.height=(clamp(main-0.03,0,1)*100)+\"%\";}\n    requestAnimationFrame(loop);\n  }\n\n  // missões\n  const M=[\n    { t:''Toque a música de fundo: clique <b>Conectar notebook (P2→P10)</b> e suba o <b>fader</b> do canal Notebook (linha estéreo) acima de 60.'',\n      ok:()=>{const l=by(\"ln\");return l.conn&&l.on&&l.fader>=60;} },\n    { t:''Ganho sem estourar: no <b>Mic 1</b>, suba o <b>GANHO</b> — mas se o <b>PEAK</b> vermelho acender, abaixe. Deixe o ganho forte, porém sem clip (entre 55 e 70).'',\n      ok:()=>{const c=by(\"c1\");return c.gain>=55&&c.gain<=70&&!c.peak;} },\n    { t:''Voz abafada: no <b>Mic 1</b>, use o EQ de 3 bandas — realce o <b>HIGH</b> (+4 ou mais) e reduza o <b>LOW</b> (−4 ou menos).'',\n      ok:()=>{const c=by(\"c1\");return c.hi>=4&&c.lo<=-4;} },\n    { t:''Abra o canal na mistura: suba o <b>fader</b> do <b>Mic 1</b> acima de 60 e garanta que ele está <b>ON</b>.'',\n      ok:()=>{const c=by(\"c1\");return c.on&&c.fader>=60;} },\n    { t:''Retorno do palestrante: mande o <b>Mic 1</b> para o <b>AUX</b> (monitor) — gire o AUX acima de 40.'',\n      ok:()=>{const c=by(\"c1\");return c.aux>=40;} },\n  ];\n  let mi=0;\n  function paintM(){const idx=$(\"mIdx\"),txt=$(\"mTxt\");\n    if(mi>=M.length){idx.textContent=\"CONCLUÍDO\";txt.innerHTML=\"🎓 <b>Mandou bem!</b> Você operou uma mesa analógica: notebook via P2→P10, ganho sem clip, EQ de 3 bandas e retorno.\";$(\"mSkip\").style.display=\"none\";return;}\n    idx.textContent=\"MISSÃO \"+(mi+1)+\"/\"+M.length;txt.innerHTML=M[mi].t;}\n  function check(){if(mi>=M.length)return;try{if(M[mi].ok()){mi++;$(\"verdict\").textContent=\"✔ Feito!\";$(\"verdict\").className=\"verdict good\";setTimeout(()=>{$(\"verdict\").textContent=\"\";},1200);paintM();}}catch(e){}}\n  $(\"mSkip\").onclick=()=>{if(mi<M.length){mi++;paintM();}};\n\n  setupInteraction();render();paintM();requestAnimationFrame(loop);\n})();\n</script>\n</body>\n</html>\n"}]'::jsonb);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values
  ('e6b50000-b551-4c00-9000-0000000b0011','e6b50000-b551-4c00-9000-0000000000a2','Amplificação e potência: watts, ohms e ligação segura','texto','<p><strong>O amplificador é quem dá força ao som.</strong> O sinal que sai da mesa é fraco (nível de linha) — não move um alto-falante. O <strong>amplificador de potência</strong> pega esse sinal e o transforma em potência elétrica capaz de empurrar o cone da caixa e encher o ambiente. Entender o amplificador é o que separa quem "liga na sorte" de quem monta um sistema seguro e com som firme.</p>
insert into public.quizzes (id,lesson_id,titulo) values ('e6b50000-b551-4c00-9000-0000000c0011','e6b50000-b551-4c00-9000-0000000b0011','Quiz — Amplificação e potência');
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('e6b50000-b551-4c00-9000-000000000b01','e6b50000-b551-4c00-9000-0000000c0011','Qual a diferença entre caixa ativa e passiva?','A ativa tem o amplificador embutido; a passiva precisa de um amplificador externo entre a mesa e a caixa.',1,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000b01','Ativa é maior; passiva é menor',false,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000b01','Ativa tem amplificador embutido; passiva precisa de amplificador externo',true,2);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000b01','Só a cor muda',false,3);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000b01','Ativa é sem fio',false,4);
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('e6b50000-b551-4c00-9000-000000000b02','e6b50000-b551-4c00-9000-0000000c0011','Ao escolher a potência do amplificador para uma caixa passiva, o ideal é:','RMS um pouco maior que o da caixa (≈1,5–2×). Amplificador folgado trabalha limpo; pequeno demais clipa e queima drivers.',2,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000b02','Bem menor que a caixa',false,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000b02','RMS um pouco maior que o da caixa (folga)',true,2);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000b02','Não importa a potência',false,3);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000b02','O maior PMPO possível',false,4);
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('e6b50000-b551-4c00-9000-000000000b03','e6b50000-b551-4c00-9000-0000000c0011','O que realmente costuma QUEIMAR um alto-falante?','O sinal distorcido (clipping) de um amplificador forçado — não o volume alto e limpo.',3,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000b03','Volume alto e limpo',false,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000b03','O sinal distorcido (clipping)',true,2);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000b03','Cabo Speakon',false,3);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000b03','Phantom power',false,4);
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('e6b50000-b551-4c00-9000-000000000b04','e6b50000-b551-4c00-9000-0000000c0011','Ligar duas caixas de 8 Ω em paralelo resulta em:','4 Ω. Paralelo abaixa a impedância; nunca fique abaixo da impedância mínima do amplificador.',4,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000b04','16 Ω',false,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000b04','4 Ω',true,2);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000b04','8 Ω',false,3);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000b04','0 Ω',false,4);
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('e6b50000-b551-4c00-9000-000000000b05','e6b50000-b551-4c00-9000-0000000c0011','A saída de potência do amplificador (para a caixa passiva) usa:','Cabo de potência (Speakon travável ou P10 de alta seção). Nunca ligue essa saída numa entrada da mesa.',5,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000b05','Cabo de microfone fino',false,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000b05','Cabo de potência (Speakon/P10 de alta seção)',true,2);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000b05','Cabo P2 de fone',false,3);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000b05','Cabo de rede',false,4);
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('e6b50000-b551-4c00-9000-000000000b06','e6b50000-b551-4c00-9000-0000000c0011','O knob de nível do amplificador serve para:','É ganho: deixe num ponto fixo e seguro. O volume do show você faz na mesa; vigie o LED de CLIP.',6,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000b06','Ser o volume do show',false,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000b06','Ficar num ponto fixo e seguro (o volume é na mesa)',true,2);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000b06','Ligar o phantom',false,3);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000b06','Trocar a impedância',false,4);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values
  ('e6b50000-b551-4c00-9000-0000000b0012','e6b50000-b551-4c00-9000-0000000000a2','PA de menor porte: caixa ativa × passiva, amplificação e posicionamento','texto','<p><strong>PA (Public Address) é o sistema que leva o som para o público.</strong> Em eventos menores — palestras, cultos, festas — você geralmente monta um PA simples: uma ou duas caixas para a plateia e, às vezes, um retorno para quem fala. Saber montar isso certo (e por que) evita os dois maiores perrengues: <strong>não sair som</strong> e <strong>microfonia</strong>.</p>
insert into public.quizzes (id,lesson_id,titulo) values ('e6b50000-b551-4c00-9000-0000000c0012','e6b50000-b551-4c00-9000-0000000b0012','Quiz — PA e caixas');
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('e6b50000-b551-4c00-9000-000000000c01','e6b50000-b551-4c00-9000-0000000c0012','Uma caixa acústica ATIVA:','A caixa ativa tem amplificador embutido — liga direto na saída da mesa. Só precisa de energia (tomada).',1,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000c01','Precisa de amplificador externo',false,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000c01','Tem amplificador embutido e liga direto na mesa',true,2);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000c01','Não funciona em eventos',false,3);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000c01','Só toca graves',false,4);
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('e6b50000-b551-4c00-9000-000000000c02','e6b50000-b551-4c00-9000-0000000c0012','Para uma caixa PASSIVA funcionar, o caminho correto é:','A passiva não tem amplificador; precisa de um amplificador externo: Mesa → Amplificador → Caixa Passiva.',2,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000c02','Mesa → Caixa Passiva (direto)',false,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000c02','Mesa → Amplificador → Caixa Passiva',true,2);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000c02','Caixa Passiva → Mesa',false,3);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000c02','Não precisa de nada',false,4);
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('e6b50000-b551-4c00-9000-000000000c03','e6b50000-b551-4c00-9000-0000000c0012','Para evitar microfonia, as caixas de PA devem ficar:','À frente dos microfones, apontando para a plateia. Caixa atrás ou apontando para o mic realimenta e apita.',3,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000c03','Atrás dos microfones',false,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000c03','À frente dos microfones, apontando para a plateia',true,2);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000c03','Em cima dos microfones',false,3);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000c03','Não importa a posição',false,4);
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('e6b50000-b551-4c00-9000-000000000c04','e6b50000-b551-4c00-9000-0000000c0012','O subgrave (sub) serve para:','Reforçar as frequências graves (o ''peso'' do som). Útil em música/festa; numa palestra só de fala, muitas vezes nem é necessário.',4,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000c04','Deixar a voz mais aguda',false,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000c04','Reforçar as frequências graves',true,2);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000c04','Substituir o amplificador',false,3);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000c04','Evitar microfonia sozinho',false,4);
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('e6b50000-b551-4c00-9000-000000000c05','e6b50000-b551-4c00-9000-0000000c0012','Ligar a saída de um amplificador de potência numa caixa ATIVA é:','Errado e perigoso: a caixa ativa já tem amplificador interno. Enviar nível de alto-falante nela pode danificar o equipamento.',5,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000c05','Recomendado, dá mais volume',false,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000c05','Errado e pode danificar — a ativa já tem amplificador',true,2);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000c05','Necessário sempre',false,3);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000c05','Indiferente',false,4);
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('e6b50000-b551-4c00-9000-000000000c06','e6b50000-b551-4c00-9000-0000000c0012','Num evento pequeno (palestra), um arranjo típico de PA é:','Uma ou duas caixas de PA para a plateia (à frente, em tripé) e um AUX/retorno para o apresentador se ouvir, se necessário.',6,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000c06','Dez caixas ao redor da plateia',false,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000c06','Uma/duas caixas para a plateia + um retorno (AUX) para o apresentador',true,2);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000c06','Só o notebook, sem caixas',false,3);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e6b50000-b551-4c00-9000-000000000c06','Caixas apontando para o microfone',false,4);
insert into public.ai_animations (lesson_id,tipo,status,model,roteiro,urls) values ('e6b50000-b551-4c00-9000-0000000b0012','interactive','ready','handcrafted-interactive','{"titulo":"Simulador — Montando o PA","cenas":[{"numero":1,"titulo":"Simulador — Montando o PA","modo":"widget","narracao":"Monte a cadeia de saída (ativa × passiva), posicione contra microfonia e adicione o sub. Complete as 4 missões.","explicacao_texto":"Monte a cadeia de saída (ativa × passiva), posicione contra microfonia e adicione o sub. Complete as 4 missões.","destaques":["Caixa ativa liga direto","Passiva precisa de amplificador","Caixas à frente dos mics","Subgrave para os graves"]}]}'::jsonb,'[{"html":"<!doctype html>\n<html lang=\"pt-BR\">\n<head>\n<meta charset=\"utf-8\">\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1\">\n<title>Simulador — Montando o PA (SMU)</title>\n<style>\n  :root{--bg:#0b0f17;--panel:#151b28;--panel2:#0f1420;--line:#26344c;--ink:#e7ecf5;\n    --muted:#8ea0bd;--amber:#F59E0B;--green:#22c55e;--red:#ef4444;--cyan:#22d3ee}\n  *{box-sizing:border-box}html,body{margin:0}\n  body{background:var(--bg);color:var(--ink);font-family:\"Space Grotesk\",system-ui,-apple-system,\"Segoe UI\",Roboto,sans-serif;\n    -webkit-font-smoothing:antialiased;padding:10px;user-select:none}\n  h1{font-size:15px;margin:0 0 2px}.sub{font-size:11.5px;color:var(--muted);margin-bottom:10px}\n  .mission{display:flex;gap:10px;align-items:center;background:#0c1220;border:1px solid var(--line);border-radius:10px;padding:9px 12px;margin-bottom:12px}\n  .mission .idx{font-size:10px;color:var(--amber);font-weight:800;letter-spacing:.8px;white-space:nowrap}\n  .mission .txt{font-size:12.5px;line-height:1.3;flex:1}.mission .txt b{color:var(--amber)}\n  .mission button{font:inherit;font-size:11px;color:var(--muted);background:transparent;border:1px solid var(--line);border-radius:7px;padding:6px 9px;cursor:pointer}\n  .grid{display:flex;gap:14px;flex-wrap:wrap}\n  .card{background:linear-gradient(180deg,var(--panel),var(--panel2));border:1px solid var(--line);border-radius:12px;padding:14px;flex:1 1 320px}\n  .card h3{margin:0 0 10px;font-size:11px;letter-spacing:1px;color:var(--muted);text-transform:uppercase}\n  .chain{display:flex;align-items:center;gap:8px;flex-wrap:wrap;min-height:64px;background:#0c1220;border:1px dashed var(--line);border-radius:10px;padding:12px}\n  .node{background:#111a2b;border:1px solid var(--line);border-radius:9px;padding:8px 12px;font-size:12px;font-weight:700;text-align:center;position:relative}\n  .node .em{font-size:20px;display:block}\n  .node.mesa{border-color:var(--amber)}\n  .node.rm{cursor:pointer}\n  .node .x{position:absolute;top:-7px;right:-7px;width:18px;height:18px;border-radius:50%;background:var(--red);color:#fff;font-size:11px;line-height:18px;text-align:center}\n  .arrow{color:#33456a;font-size:18px}\n  .palette{display:flex;gap:8px;flex-wrap:wrap;margin-top:10px}\n  .pbtn{font:inherit;font-size:12px;font-weight:700;padding:9px 12px;border-radius:9px;border:1px solid var(--line);background:#0c1220;color:var(--ink);cursor:pointer}\n  .pbtn .em{margin-right:5px}\n  .row{display:flex;gap:8px;flex-wrap:wrap;margin-top:8px}\n  .opt{font:inherit;font-size:12px;font-weight:700;padding:9px 12px;border-radius:9px;border:1px solid var(--line);background:#0c1220;color:var(--ink);cursor:pointer}\n  .opt.sel{border-color:var(--amber);background:#1a1608}.opt.sub.on{border-color:var(--green);background:#0e1a10;color:var(--green)}\n  .stage{position:relative;height:150px;background:#0c1220;border:1px solid var(--line);border-radius:10px;margin-top:8px;overflow:hidden}\n  .stage .aud{position:absolute;left:0;right:0;bottom:0;height:34px;background:#0e1524;border-top:1px solid var(--line);font-size:10px;color:var(--muted);display:flex;align-items:center;justify-content:center}\n  .stage .mic{position:absolute;left:50%;top:64px;transform:translateX(-50%);font-size:22px}\n  .stage .spk{position:absolute;font-size:22px;transition:.25s}\n  .verdict{font-size:12.5px;font-weight:700;min-height:18px;margin-top:8px}.verdict.good{color:var(--green)}.verdict.bad{color:var(--red)}\n</style>\n</head>\n<body>\n  <h1>Montando o PA do evento</h1>\n  <div class=\"sub\">Ligue as caixas do jeito certo (ativa × passiva), posicione contra microfonia e reforce os graves.</div>\n  <div class=\"mission\">\n    <span class=\"idx\" id=\"mIdx\">MISSÃO 1/4</span>\n    <span class=\"txt\" id=\"mTxt\">—</span>\n    <button id=\"mSkip\">Pular</button>\n  </div>\n\n  <div class=\"grid\">\n    <div class=\"card\">\n      <h3>Cadeia de saída (da mesa até a caixa)</h3>\n      <div class=\"chain\" id=\"chain\"></div>\n      <div class=\"palette\" id=\"palette\">\n        <button class=\"pbtn\" data-add=\"ativa\"><span class=\"em\">🔊</span>Caixa Ativa</button>\n        <button class=\"pbtn\" data-add=\"amp\"><span class=\"em\">🧯</span>Amplificador</button>\n        <button class=\"pbtn\" data-add=\"passiva\"><span class=\"em\">📦</span>Caixa Passiva</button>\n        <button class=\"pbtn\" data-add=\"sub\"><span class=\"em\">🔈</span>Subgrave</button>\n      </div>\n      <div class=\"row\"><button class=\"pbtn\" id=\"clear\">↺ Limpar cadeia</button></div>\n      <div class=\"verdict\" id=\"v1\"></div>\n    </div>\n\n    <div class=\"card\" style=\"flex:1 1 260px\">\n      <h3>Posicionamento (contra microfonia)</h3>\n      <div class=\"row\">\n        <button class=\"opt\" data-pos=\"frente\">Caixas à FRENTE dos mics</button>\n        <button class=\"opt\" data-pos=\"atras\">Caixas ATRÁS dos mics</button>\n      </div>\n      <div class=\"stage\" id=\"stage\">\n        <div class=\"spk\" id=\"spk1\">🔊</div><div class=\"spk\" id=\"spk2\">🔊</div>\n        <div class=\"mic\">🎤</div>\n        <div class=\"aud\">👥 plateia</div>\n      </div>\n      <div class=\"verdict\" id=\"v2\"></div>\n    </div>\n  </div>\n\n<script>\n\"use strict\";\n(function(){\n  const $=id=>document.getElementById(id);\n  const NODE={ativa:{em:\"🔊\",nm:\"Caixa Ativa\"},amp:{em:\"🧯\",nm:\"Amplificador\"},passiva:{em:\"📦\",nm:\"Caixa Passiva\"},sub:{em:\"🔈\",nm:\"Subgrave\"}};\n  const state={chain:[],pos:null};\n\n  function renderChain(){\n    const c=$(\"chain\");c.innerHTML=\"\";\n    const mesa=document.createElement(\"div\");mesa.className=\"node mesa\";mesa.innerHTML=''<span class=\"em\">🎛️</span>Mesa'';c.appendChild(mesa);\n    state.chain.forEach((k,i)=>{ const a=document.createElement(\"span\");a.className=\"arrow\";a.textContent=\"➜\";c.appendChild(a);\n      const n=document.createElement(\"div\");n.className=\"node rm\";n.innerHTML=`<span class=\"em\">${NODE[k].em}</span>${NODE[k].nm}<span class=\"x\">×</span>`;\n      n.onclick=()=>{state.chain.splice(i,1);renderChain();check();};c.appendChild(n); });\n    validateChain();\n  }\n  function validateChain(){\n    const v=$(\"v1\"); const ch=state.chain.filter(x=>x!==\"sub\");\n    const hasSub=state.chain.includes(\"sub\");\n    // regras\n    let msg=\"\",cls=\"\";\n    if(ch.length===0){ msg=\"Adicione as caixas para completar o caminho do som.\"; cls=\"\"; }\n    else if(ch.join()===\"ativa\"){ msg=\"✔ Correto! Mesa → Caixa Ativa (a caixa ativa já tem amplificador dentro).\"; cls=\"good\"; }\n    else if(ch.join()===\"amp,passiva\"){ msg=\"✔ Correto! Mesa → Amplificador → Caixa Passiva (a passiva precisa do amp).\"; cls=\"good\"; }\n    else if(ch.join()===\"passiva\"){ msg=\"✖ A caixa passiva não tem amplificador — sem som. Coloque um Amplificador antes dela.\"; cls=\"bad\"; }\n    else if(ch.join()===\"amp,ativa\"||ch.join()===\"ativa,amp\"){ msg=\"✖ Caixa ativa já tem amp interno — não precisa (e não deve) de amplificador antes.\"; cls=\"bad\"; }\n    else if(ch.join()===\"amp\"){ msg=\"Falta a caixa. Amplificador sozinho não toca — ligue uma Caixa Passiva depois.\"; cls=\"\"; }\n    else { msg=\"Cadeia incomum. O certo é: Mesa → Caixa Ativa, OU Mesa → Amplificador → Caixa Passiva.\"; cls=\"bad\"; }\n    if(hasSub&&cls===\"good\") msg+=\" Subgrave adicionado 🔈 — reforço de graves ok.\";\n    v.textContent=msg;v.className=\"verdict \"+cls;\n  }\n  $(\"palette\").querySelectorAll(\"[data-add]\").forEach(b=>b.onclick=()=>{ state.chain.push(b.dataset.add);renderChain();check(); });\n  $(\"clear\").onclick=()=>{state.chain=[];renderChain();check();};\n\n  // posicionamento\n  function renderPos(){\n    const s1=$(\"spk1\"),s2=$(\"spk2\");\n    document.querySelectorAll(\"[data-pos]\").forEach(o=>o.classList.toggle(\"sel\",o.dataset.pos===state.pos));\n    if(state.pos===\"frente\"){ s1.style.left=\"12%\";s1.style.top=\"96px\";s2.style.left=\"80%\";s2.style.top=\"96px\"; }\n    else if(state.pos===\"atras\"){ s1.style.left=\"18%\";s1.style.top=\"24px\";s2.style.left=\"74%\";s2.style.top=\"24px\"; }\n    else { s1.style.left=\"12%\";s1.style.top=\"24px\";s2.style.left=\"80%\";s2.style.top=\"24px\";s2.style.opacity=\"0.3\";s1.style.opacity=\"0.3\"; }\n    if(state.pos){ s1.style.opacity=\"1\";s2.style.opacity=\"1\"; }\n    const v=$(\"v2\");\n    if(state.pos===\"frente\"){ v.textContent=\"✔ Certo! As caixas à frente dos microfones (apontando para a plateia) reduzem a microfonia.\"; v.className=\"verdict good\"; }\n    else if(state.pos===\"atras\"){ v.textContent=\"✖ Perigo de microfonia! Caixas atrás/apontando para os microfones realimentam e apitam.\"; v.className=\"verdict bad\"; }\n    else v.textContent=\"\";\n  }\n  document.querySelectorAll(\"[data-pos]\").forEach(o=>o.onclick=()=>{state.pos=o.dataset.pos;renderPos();check();});\n\n  // missões\n  const okActive=()=>state.chain.filter(x=>x!==\"sub\").join()===\"ativa\";\n  const okPassive=()=>state.chain.filter(x=>x!==\"sub\").join()===\"amp,passiva\";\n  const M=[\n    { t:''Monte o PA com uma <b>caixa ATIVA</b>: a cadeia deve ser <b>Mesa → Caixa Ativa</b> (a ativa já tem amplificador).'', ok:okActive },\n    { t:''Agora com <b>caixa PASSIVA</b>: ela precisa de <b>Amplificador</b> antes. Monte <b>Mesa → Amplificador → Caixa Passiva</b>. (limpe a cadeia primeiro)'', ok:okPassive },\n    { t:''Posicionamento: coloque as caixas <b>à FRENTE</b> dos microfones (painel da direita) para evitar microfonia.'', ok:()=>state.pos===\"frente\" },\n    { t:''Reforce os graves: adicione um <b>Subgrave</b> à cadeia (mantendo a ligação correta).'', ok:()=>state.chain.includes(\"sub\")&&(okActive()||okPassive()) },\n  ];\n  let mi=0;\n  function paintM(){const idx=$(\"mIdx\"),txt=$(\"mTxt\");\n    if(mi>=M.length){idx.textContent=\"CONCLUÍDO\";txt.innerHTML=\"🎓 <b>Boa!</b> Você sabe montar um PA pequeno: ativa liga direto, passiva precisa de amplificador, caixas à frente dos mics e sub para os graves.\";$(\"mSkip\").style.display=\"none\";return;}\n    idx.textContent=\"MISSÃO \"+(mi+1)+\"/\"+M.length;txt.innerHTML=M[mi].t;}\n  function check(){if(mi>=M.length)return;try{if(M[mi].ok()){mi++;paintM();}}catch(e){}}\n  $(\"mSkip\").onclick=()=>{if(mi<M.length){mi++;paintM();}};\n\n  renderChain();renderPos();paintM();\n})();\n</script>\n</body>\n</html>\n"}]'::jsonb);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values
  ('e6b50000-b551-4c00-9000-0000000b0013','e6b50000-b551-4c00-9000-0000000000a2','Ordem de ligar e desligar o sistema (proteja as caixas)','texto','<p><strong>Existe uma ordem certa para ligar e desligar um sistema de som</strong> — e ignorá-la é uma das formas mais comuns (e caras) de <strong>danificar caixas</strong>. É uma regra simples de decorar e que separa o amador do profissional. Vamos entender o porquê e a sequência.</p>
