insert into public.ai_animations (lesson_id,tipo,status,model,roteiro,urls) values ('e6b50000-b551-4c00-9000-0000000b0013','interactive','ready','handcrafted-interactive','{"titulo":"Simulador — Ordem de ligar o sistema","cenas":[{"numero":1,"titulo":"Simulador — Ordem de ligar o sistema","modo":"widget","narracao":"Ligue na ordem certa (fontes→mesa→amplificação) e desligue no inverso, sem estouro. Complete as 2 missões.","explicacao_texto":"Ligue na ordem certa (fontes→mesa→amplificação) e desligue no inverso, sem estouro. Complete as 2 missões.","destaques":["Amplificação liga por último","Amplificação desliga primeiro","O ''tump'' que danifica caixas"]}]}'::jsonb,'[{"html":"<!doctype html>\n<html lang=\"pt-BR\">\n<head>\n<meta charset=\"utf-8\">\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1\">\n<title>Simulador — Ordem de ligar o sistema (SMU)</title>\n<style>\n  :root{--bg:#0b0f17;--panel:#151b28;--panel2:#0f1420;--line:#26344c;--ink:#e7ecf5;\n    --muted:#8ea0bd;--amber:#F59E0B;--green:#22c55e;--red:#ef4444;--cyan:#22d3ee}\n  *{box-sizing:border-box}html,body{margin:0}\n  body{background:var(--bg);color:var(--ink);font-family:\"Space Grotesk\",system-ui,-apple-system,\"Segoe UI\",Roboto,sans-serif;\n    -webkit-font-smoothing:antialiased;padding:10px;user-select:none}\n  h1{font-size:15px;margin:0 0 2px}.sub{font-size:11.5px;color:var(--muted);margin-bottom:10px}\n  .mission{display:flex;gap:10px;align-items:center;background:#0c1220;border:1px solid var(--line);border-radius:10px;padding:9px 12px;margin-bottom:12px}\n  .mission .idx{font-size:10px;color:var(--amber);font-weight:800;letter-spacing:.8px;white-space:nowrap}\n  .mission .txt{font-size:12.5px;line-height:1.3;flex:1}.mission .txt b{color:var(--amber)}\n  .mission button{font:inherit;font-size:11px;color:var(--muted);background:transparent;border:1px solid var(--line);border-radius:7px;padding:6px 9px;cursor:pointer}\n  .devs{display:flex;gap:12px;justify-content:center;flex-wrap:wrap;margin:14px 0}\n  .dev{flex:1 1 150px;max-width:210px;background:linear-gradient(180deg,var(--panel),var(--panel2));border:1px solid var(--line);border-radius:14px;padding:16px;text-align:center;position:relative}\n  .dev .em{font-size:40px}.dev .nm{font-size:13px;font-weight:700;margin-top:4px}.dev .role{font-size:10px;color:var(--muted)}\n  .dev .order{position:absolute;top:8px;left:10px;font-size:10px;color:var(--muted);border:1px solid var(--line);border-radius:20px;padding:2px 7px}\n  .led{width:12px;height:12px;border-radius:50%;background:#3a2020;margin:8px auto 0;box-shadow:inset 0 0 3px #000}\n  .led.on{background:var(--green);box-shadow:0 0 10px var(--green)}\n  .pw{font:inherit;font-size:12px;font-weight:800;padding:9px 0;width:100%;margin-top:10px;border-radius:9px;border:1px solid var(--line);background:#0c1220;color:var(--muted);cursor:pointer}\n  .pw.on{background:var(--green);border-color:var(--green);color:#08120a}\n  .spkbox{text-align:center;margin:6px 0 4px}\n  .spk{font-size:34px;display:inline-block;transition:transform .08s}\n  .spk.pop{animation:shake .4s}\n  @keyframes shake{0%,100%{transform:translateX(0)}20%{transform:translateX(-6px) scale(1.1)}40%{transform:translateX(6px) scale(1.15)}60%{transform:translateX(-4px)}80%{transform:translateX(4px)}}\n  .status{text-align:center;font-size:13px;font-weight:700;min-height:22px}\n  .status.good{color:var(--green)}.status.bad{color:var(--red)}\n  .pop-flash{position:fixed;inset:0;background:radial-gradient(circle,rgba(239,68,68,.35),transparent 60%);opacity:0;pointer-events:none;transition:opacity .1s;z-index:5}\n  .pop-flash.show{opacity:1}\n  .phasetag{text-align:center;font-size:11px;color:var(--muted);margin-bottom:6px}\n</style>\n</head>\n<body>\n  <h1>Ordem de ligar (e desligar) o sistema</h1>\n  <div class=\"sub\">A amplificação liga por ÚLTIMO e desliga PRIMEIRO. Assim você evita o estouro que danifica as caixas.</div>\n  <div class=\"mission\">\n    <span class=\"idx\" id=\"mIdx\">MISSÃO 1/2</span>\n    <span class=\"txt\" id=\"mTxt\">—</span>\n    <button id=\"mSkip\">Pular</button>\n  </div>\n\n  <div class=\"phasetag\" id=\"phase\">Fase: LIGAR</div>\n  <div class=\"spkbox\"><span class=\"spk\" id=\"spk\">🔊</span></div>\n  <div class=\"devs\" id=\"devs\"></div>\n  <div class=\"status\" id=\"status\"></div>\n  <div class=\"pop-flash\" id=\"flash\"></div>\n\n<script>\n\"use strict\";\n(function(){\n  const $=id=>document.getElementById(id);\n  const DEV=[\n    {id:0,em:\"💻\",nm:\"Fontes\",role:\"notebook, players\"},\n    {id:1,em:\"🎛️\",nm:\"Mesa de som\",role:\"mixer + processadores\"},\n    {id:2,em:\"🔊\",nm:\"Amplificação\",role:\"amplificador / caixas ativas\"},\n  ];\n  const on=[false,false,false];\n  let clean=true; // sem estouro na fase atual\n\n  function render(){\n    const d=$(\"devs\");d.innerHTML=\"\";\n    DEV.forEach(v=>{ const el=document.createElement(\"div\");el.className=\"dev\";\n      el.innerHTML=`<div class=\"order\">ligar ${v.id+1}º</div><div class=\"em\">${v.em}</div>\n        <div class=\"nm\">${v.nm}</div><div class=\"role\">${v.role}</div>\n        <div class=\"led ${on[v.id]?''on'':''''}\"></div>\n        <button class=\"pw ${on[v.id]?''on'':''''}\" data-i=\"${v.id}\">${on[v.id]?''LIGADO'':''desligado''}</button>`;\n      d.appendChild(el); });\n    d.querySelectorAll(\"[data-i]\").forEach(b=>b.onclick=()=>toggle(+b.dataset.i));\n  }\n  function pop(msg){ clean=false; const f=$(\"flash\");f.classList.add(\"show\");setTimeout(()=>f.classList.remove(\"show\"),150);\n    const s=$(\"spk\");s.textContent=\"🔊💥\";s.classList.add(\"pop\");setTimeout(()=>{s.classList.remove(\"pop\");s.textContent=\"🔊\";},500);\n    $(\"status\").textContent=\"⚡ POP! \"+msg; $(\"status\").className=\"status bad\"; }\n  function toggle(i){\n    const turningOn=!on[i];\n    if(turningOn){\n      // ligar amplificação com fontes/mesa desligadas: sem perigo, mas fora de ordem\n      if(i<2 && on[2]){ pop(\"você mexeu na \"+DEV[i].nm+\" com a amplificação já ligada — o estouro vai para as caixas.\"); return; }\n      on[i]=true;\n      if(i===2 && !(on[0]&&on[1])){ $(\"status\").textContent=\"Dica: a amplificação deve ser o ÚLTIMO a ligar (ligue fontes e mesa antes).\"; $(\"status\").className=\"status bad\"; }\n      else { $(\"status\").textContent=DEV[i].nm+\" ligado.\"; $(\"status\").className=\"status good\"; }\n    } else {\n      if(i<2 && on[2]){ pop(\"desligou a \"+DEV[i].nm+\" com a amplificação ligada — estouro nas caixas. Desligue a amplificação PRIMEIRO.\"); return; }\n      on[i]=false; $(\"status\").textContent=DEV[i].nm+\" desligado.\"; $(\"status\").className=\"status good\";\n    }\n    render(); check();\n  }\n\n  const M=[\n    { phase:\"LIGAR\", t:''Ligue o sistema na <b>ordem certa</b>: 1º Fontes, 2º Mesa e por <b>último</b> a Amplificação. Sem estouro!'',\n      setup:()=>{on[0]=on[1]=on[2]=false;clean=true;$(\"phase\").textContent=\"Fase: LIGAR\";},\n      ok:()=>on[0]&&on[1]&&on[2]&&clean },\n    { phase:\"DESLIGAR\", t:''Agora <b>desligue</b> na ordem inversa: 1º a <b>Amplificação</b>, depois a Mesa e as Fontes. Sem estouro!'',\n      setup:()=>{on[0]=on[1]=on[2]=true;clean=true;$(\"phase\").textContent=\"Fase: DESLIGAR\";},\n      ok:()=>!on[0]&&!on[1]&&!on[2]&&clean },\n  ];\n  let mi=0;\n  function paintM(){const idx=$(\"mIdx\"),txt=$(\"mTxt\");\n    if(mi>=M.length){idx.textContent=\"CONCLUÍDO\";txt.innerHTML=\"🎓 <b>Perfeito!</b> Amplificação por último ao ligar, primeiro ao desligar. Esse hábito protege as caixas e evita o ''tump'' no PA.\";$(\"mSkip\").style.display=\"none\";$(\"phase\").textContent=\"\";return;}\n    idx.textContent=\"MISSÃO \"+(mi+1)+\"/\"+M.length;txt.innerHTML=M[mi].t; M[mi].setup(); render(); }\n  function check(){if(mi>=M.length)return;try{if(M[mi].ok()){mi++;$(\"status\").textContent=\"✔ Sequência correta!\";$(\"status\").className=\"status good\";setTimeout(paintM,700);}}catch(e){}}\n  $(\"mSkip\").onclick=()=>{if(mi<M.length){mi++;paintM();}};\n\n  paintM();render();\n})();\n</script>\n</body>\n</html>\n"}]'::jsonb);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values
  ('e6b50000-b551-4c00-9000-0000000b0014','e6b50000-b551-4c00-9000-0000000000a2','Passagem de som: o checklist do técnico (capstone)','texto','<p><strong>Passagem de som é o ensaio do técnico.</strong> É o momento, antes do evento começar, em que você monta, liga, ajusta e testa tudo — para que na hora "H" nada dê errado. Um bom técnico não improvisa no ar: ele chega cedo, segue um roteiro e resolve os problemas quando ainda dá tempo. Esta aula junta tudo o que você aprendeu num único fluxo prático.</p>
insert into public.quizzes (id,lesson_id,titulo) values ('e6b50000-b551-4c00-9000-0000000c0014','e6b50000-b551-4c00-9000-0000000b0014','Quiz — Passagem de som');
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('e6b50000-b551-4c00-9000-000000000e01','e6b50000-b551-4c00-9000-0000000c0014','Para que serve a passagem de som?','Para montar, ajustar e testar tudo ANTES do evento começar, resolvendo problemas enquanto ainda há tempo.',1,1);
