insert into public.ai_animations (lesson_id,tipo,status,model,roteiro,urls) values ('e6b50000-b551-4c00-9000-0000000b0014','interactive','ready','handcrafted-interactive','{"titulo":"Simulador — Passagem de som","cenas":[{"numero":1,"titulo":"Simulador — Passagem de som","modo":"widget","narracao":"Faça uma passagem de som completa: ligar na ordem, notebook, sem fio, ganho, EQ, retorno e teste. Complete os 7 itens.","explicacao_texto":"Faça uma passagem de som completa: ligar na ordem, notebook, sem fio, ganho, EQ, retorno e teste. Complete os 7 itens.","destaques":["Roteiro completo da passagem","Junta todas as habilidades","Teste final sem microfonia"]}]}'::jsonb,'[{"html":"<!doctype html>\n<html lang=\"pt-BR\">\n<head>\n<meta charset=\"utf-8\">\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1\">\n<title>Simulador — Passagem de som (SMU)</title>\n<style>\n  :root{--bg:#0b0f17;--panel:#151b28;--panel2:#0f1420;--line:#26344c;--ink:#e7ecf5;\n    --muted:#8ea0bd;--amber:#F59E0B;--green:#22c55e;--red:#ef4444;--cyan:#22d3ee}\n  *{box-sizing:border-box}html,body{margin:0}\n  body{background:var(--bg);color:var(--ink);font-family:\"Space Grotesk\",system-ui,-apple-system,\"Segoe UI\",Roboto,sans-serif;\n    -webkit-font-smoothing:antialiased;padding:10px;user-select:none}\n  h1{font-size:15px;margin:0 0 2px}.sub{font-size:11.5px;color:var(--muted);margin-bottom:10px}\n  .prog{display:flex;align-items:center;gap:10px;margin-bottom:12px}\n  .progbar{flex:1;height:12px;border-radius:6px;background:#0c1220;border:1px solid var(--line);overflow:hidden}\n  .progbar i{display:block;height:100%;width:0%;background:linear-gradient(90deg,var(--amber),var(--green));transition:width .3s}\n  .progtxt{font-size:12px;font-weight:800;color:var(--amber)}\n  .step{display:flex;gap:12px;align-items:center;background:linear-gradient(180deg,var(--panel),var(--panel2));border:1px solid var(--line);border-radius:11px;padding:11px 13px;margin-bottom:8px}\n  .step.done{border-color:var(--green)}\n  .dot{width:26px;height:26px;border-radius:50%;border:2px solid var(--line);display:flex;align-items:center;justify-content:center;font-size:13px;font-weight:800;color:var(--muted);flex:0 0 auto}\n  .step.done .dot{background:var(--green);border-color:var(--green);color:#08120a}\n  .body{flex:1;min-width:0}\n  .t{font-size:12.5px;font-weight:700}.d{font-size:10.5px;color:var(--muted)}\n  .ctrl{display:flex;gap:8px;align-items:center;margin-top:6px;flex-wrap:wrap}\n  .b{font:inherit;font-size:11px;font-weight:700;padding:7px 11px;border-radius:8px;border:1px solid var(--line);background:#0c1220;color:var(--ink);cursor:pointer}\n  .b.on{background:var(--green);border-color:var(--green);color:#08120a}\n  .b.amber{background:var(--amber);border-color:var(--amber);color:#0b0f17}\n  .b:disabled{opacity:.4;cursor:not-allowed}\n  input[type=range]{width:130px;accent-color:var(--amber);height:22px;vertical-align:middle}\n  .val{font-size:11px;font-weight:700;min-width:60px}\n  .miniled{display:inline-flex;gap:3px}.miniled i{width:12px;height:10px;border-radius:2px;background:#1a2540}.miniled i.g{background:var(--green)}.miniled i.a{background:var(--amber)}.miniled i.r{background:var(--red)}\n  .final{display:none;text-align:center;padding:16px;border-radius:12px;border:1px solid var(--green);background:#0e1a10;margin-top:8px}\n  .final.show{display:block}.final .big{font-size:18px;font-weight:800;color:var(--green)}\n</style>\n</head>\n<body>\n  <h1>Passagem de som — palestra corporativa</h1>\n  <div class=\"sub\">Junte tudo: ligar na ordem, notebook, microfones sem fio, ganho, EQ, retorno e teste final.</div>\n  <div class=\"prog\"><div class=\"progbar\"><i id=\"pfill\"></i></div><span class=\"progtxt\" id=\"ptxt\">0/7</span></div>\n  <div id=\"steps\"></div>\n  <div class=\"final\" id=\"final\"><div class=\"big\">✅ PA pronto para o evento!</div>\n    <div style=\"font-size:12px;color:var(--muted);margin-top:6px\">Você fez uma passagem de som completa: sistema ligado com segurança, fontes e microfones no nível certo, EQ e retorno ajustados e teste sem microfonia. É exatamente o que o cliente espera do técnico.</div></div>\n\n<script>\n\"use strict\";\n(function(){\n  const $=id=>document.getElementById(id);\n  const st={ powerSeq:[], nbConn:false, nbVol:0, micScan:false, gain:20, hpf:false, aux:0, tested:false };\n  const done={};\n\n  const steps=[\n    { id:\"power\", t:\"1. Ligar na ordem certa\", d:\"Clique Fontes, Mesa e Amplificação — nessa ordem (amplificação por último).\",\n      render:()=>`<button class=\"b\" data-p=\"0\">💻 Fontes</button><button class=\"b\" data-p=\"1\">🎛️ Mesa</button><button class=\"b\" data-p=\"2\">🔊 Amplificação</button><span class=\"val\" id=\"pseq\"></span>`,\n      ok:()=>st.powerSeq.join()===\"0,1,2\" },\n    { id:\"nb\", t:\"2. Notebook (P2 → P10)\", d:\"Conecte o notebook e deixe o volume dele entre 60 e 85%.\",\n      render:()=>`<button class=\"b ${st.nbConn?''on'':''''}\" id=\"nbBtn\">${st.nbConn?''✔ Conectado'':''Conectar P2→P10''}</button>\n        <input type=\"range\" id=\"nbVol\" min=\"0\" max=\"100\" value=\"${st.nbVol}\"><span class=\"val\" id=\"nbVolV\">${st.nbVol}%</span>`,\n      ok:()=>st.nbConn&&st.nbVol>=60&&st.nbVol<=85 },\n    { id:\"mic\", t:\"3. Microfone sem fio\", d:\"Ache um canal livre (SCAN) — bateria já está cheia.\",\n      render:()=>`<button class=\"b ${st.micScan?''on'':''''}\" id=\"scanBtn\">${st.micScan?''✔ Canal livre CH4'':''🔎 SCAN canal''}</button>`,\n      ok:()=>st.micScan },\n    { id:\"gain\", t:\"4. Gain staging do microfone\", d:\"Ajuste o ganho até o nível ficar no verde (nem fraco, nem estourando).\",\n      render:()=>`<input type=\"range\" id=\"gv\" min=\"0\" max=\"100\" value=\"${st.gain}\"><span class=\"miniled\" id=\"gled\"></span><span class=\"val\" id=\"gvV\"></span>`,\n      ok:()=>st.gain>=55&&st.gain<=75 },\n    { id:\"hpf\", t:\"5. EQ da voz (HPF)\", d:\"Ligue o HPF para tirar o grave desnecessário da voz.\",\n      render:()=>`<button class=\"b ${st.hpf?''on'':''''}\" id=\"hpfBtn\">${st.hpf?''✔ HPF ligado (100 Hz)'':''Ligar HPF''}</button>`,\n      ok:()=>st.hpf },\n    { id:\"aux\", t:\"6. Retorno do apresentador (AUX)\", d:\"Mande um pouco do microfone para o monitor do apresentador.\",\n      render:()=>`<input type=\"range\" id=\"av\" min=\"0\" max=\"100\" value=\"${st.aux}\"><span class=\"val\" id=\"avV\">${st.aux}</span>`,\n      ok:()=>st.aux>=40 },\n    { id:\"test\", t:\"7. Teste final\", d:\"Fale no microfone e confira: som na caixa, sem microfonia.\",\n      render:()=>`<button class=\"b amber\" id=\"testBtn\" ${allButTest()?'''':''disabled''}>🎤 Testar \\\"1, 2, 3...\\\"</button><span class=\"val\" id=\"testV\"></span>`,\n      ok:()=>st.tested },\n  ];\n  function allButTest(){ return steps.slice(0,6).every(s=>s.ok()); }\n\n  function render(){\n    const c=$(\"steps\");c.innerHTML=\"\";\n    steps.forEach((s,i)=>{ const el=document.createElement(\"div\");el.className=\"step\"+(s.ok()?\" done\":\"\");\n      el.innerHTML=`<div class=\"dot\">${s.ok()?\"✓\":(i+1)}</div><div class=\"body\"><div class=\"t\">${s.t}</div><div class=\"d\">${s.d}</div><div class=\"ctrl\">${s.render()}</div></div>`;\n      c.appendChild(el); });\n    wire(); updateProg();\n  }\n  function gledPaint(){ const el=$(\"gled\"); if(!el)return; const n= st.gain<30?1: st.gain<55?2: st.gain<=75?4: 5;\n    const cls= st.gain<55?\"a\": st.gain<=75?\"g\":\"r\"; el.innerHTML=\"\";\n    for(let i=0;i<5;i++){const b=document.createElement(\"i\"); if(i<n)b.className=cls; el.appendChild(b);}\n    const v=$(\"gvV\"); if(v)v.textContent= st.gain<55?\"fraco\": st.gain<=75?\"bom ✓\":\"estourando\";\n  }\n  function wire(){\n    document.querySelectorAll(\"[data-p]\").forEach(b=>b.onclick=()=>{ const i=+b.dataset.p;\n      if(!st.powerSeq.includes(i))st.powerSeq.push(i); $(\"pseq\")&&($(\"pseq\").textContent=st.powerSeq.map(x=>[\"Fontes\",\"Mesa\",\"Amp\"][x]).join(\" → \"));\n      if(st.powerSeq.length===3&&st.powerSeq.join()!==\"0,1,2\"){ st.powerSeq=[]; $(\"pseq\").textContent=\"ordem errada — recomece (amplificação por último)\"; }\n      render(); });\n    const nb=$(\"nbBtn\"); if(nb)nb.onclick=()=>{st.nbConn=!st.nbConn;render();};\n    const nbv=$(\"nbVol\"); if(nbv)nbv.oninput=()=>{st.nbVol=+nbv.value;$(\"nbVolV\").textContent=st.nbVol+\"%\";checkOnly();};\n    const sc=$(\"scanBtn\"); if(sc)sc.onclick=()=>{st.micScan=true;render();};\n    const gv=$(\"gv\"); if(gv)gv.oninput=()=>{st.gain=+gv.value;gledPaint();checkOnly();};\n    const hb=$(\"hpfBtn\"); if(hb)hb.onclick=()=>{st.hpf=!st.hpf;render();};\n    const av=$(\"av\"); if(av)av.oninput=()=>{st.aux=+av.value;$(\"avV\").textContent=st.aux;checkOnly();};\n    const tb=$(\"testBtn\"); if(tb)tb.onclick=()=>{ if(allButTest()){st.tested=true;$(\"testV\").textContent=\"✔ som limpo, sem microfonia!\";render();} };\n    gledPaint();\n  }\n  function checkOnly(){ // atualiza dots/prog sem re-render (evita perder foco do slider)\n    steps.forEach((s,i)=>{ const el=$(\"steps\").children[i]; if(!el)return; el.classList.toggle(\"done\",s.ok());\n      el.querySelector(\".dot\").textContent=s.ok()?\"✓\":(i+1); });\n    const tb=$(\"testBtn\"); if(tb)tb.disabled=!allButTest();\n    updateProg();\n  }\n  function updateProg(){ const n=steps.filter(s=>s.ok()).length; $(\"pfill\").style.width=(n/steps.length*100)+\"%\"; $(\"ptxt\").textContent=n+\"/\"+steps.length;\n    $(\"final\").classList.toggle(\"show\",n===steps.length); }\n\n  render();\n})();\n</script>\n</body>\n</html>\n"}]'::jsonb);
